INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('9fff75f2-c436-4516-94eb-62fa03ff0ac4', '052c79a7-6c65-41c8-b3e1-c2dd03bb5bea', 'Pasar Antik Jl. Surabaya', 'Surga barang antik di Jakarta berupa deretan kios yang menjual perabotan vintage, keramik kuno, uang koleksi, lukisan lama, dan berbagai memorabilia bersejarah Indonesia.', 'Jl. Surabaya, Menteng, Jakarta Pusat', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/9fff75f2-c436-4516-94eb-62fa03ff0ac4.webp', true, '2026-05-20 14:52:00', '2026-05-20 16:28:55', -6.2005954, 106.8407072, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('1195a55b-4bb7-485a-ae2c-06d2efee5c7c', '780daaaa-9f43-48c5-b7c9-b38c768ff4dd', 'Batik Komar', 'Galeri batik Bandung yang terkenal dengan motif inovatif dan teknik pewarnaan alami. Pengunjung bisa melihat proses pembuatan batik langsung dan mengikuti workshop membatik.', 'Jl. Cigadung Raya Barat No.18, Bandung', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/1195a55b-4bb7-485a-ae2c-06d2efee5c7c.webp', true, '2026-05-20 14:52:03', '2026-05-20 16:28:58', -6.8874010, 107.6293992, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('9bba9686-7f58-4db0-a69b-fc35c3e47730', '052c79a7-6c65-41c8-b3e1-c2dd03bb5bea', 'Bubur Ayam Senen H. Muhtadi', 'Bubur ayam legendaris yang sudah melayani pelanggan sejak generasi ke generasi. Bubur lembut dengan topping cakwe, kacang, bawang goreng, dan kaldu ayam yang gurih.', 'Jl. Pasar Senen, Jakarta Pusat', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/9bba9686-7f58-4db0-a69b-fc35c3e47730.webp', true, '2026-05-20 14:52:00', '2026-05-20 16:29:00', -6.1758776, 106.8425769, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('43a89d01-79c3-4227-b668-679f732710fa', 'd475371a-cb92-4314-ba8b-83561f5e6f8a', 'Batik Trusmi', 'Pusat batik terbesar di Cirebon di Kampung Trusmi yang sudah ada sejak ratusan tahun. Motif mega mendung yang khas Cirebon tersedia dalam berbagai kualitas dan harga. Pengunjung bisa melihat langsung proses membatik dan belanja langsung dari pengrajin.', 'Desa Trusmi Kulon, Plered, Cirebon', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/43a89d01-79c3-4227-b668-679f732710fa.webp', true, '2026-05-20 14:52:43', '2026-05-20 16:31:30', -6.7049479, 108.5554042, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('fe6c58ed-8a50-4592-ad70-af99f7c95c7b', '962460e6-c222-4725-a275-1e7a8846019f', 'Sroto Sokaraja Pak Bambang', 'Sroto (soto) khas Banyumas dengan kuah kacang yang gurih dan kental, dipadukan dengan ketupat, soun, tauge, dan daging ayam/sapi. Sambal kacang yang unik menjadi pembeda utama sroto Sokaraja dari soto-soto lain di Jawa.', 'Jl. Raya Sokaraja, Sokaraja, Banyumas', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/fe6c58ed-8a50-4592-ad70-af99f7c95c7b.webp', true, '2026-05-20 14:52:49', '2026-05-20 16:32:49', -7.4497198, 109.2626790, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('24606115-6f1b-454c-8cb6-d4a5fcedd25d', '2cdfd1f7-ea94-4248-8f39-24478e961033', 'Candi Penataran', 'Kompleks candi Hindu terbesar di Jawa Timur yang dibangun pada masa Kerajaan Kediri hingga Majapahit (abad 12–15). Terdiri dari puluhan bangunan dengan relief cerita Ramayana dan Mahabharata yang menakjubkan.', 'Desa Penataran, Nglegok, Blitar', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/24606115-6f1b-454c-8cb6-d4a5fcedd25d.webp', true, '2026-05-20 14:52:54', '2026-05-20 16:32:51', -8.0149624, 112.2123601, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('b6ffd83d-5a41-4d12-a783-8c12b82958fc', '90516e78-cfbe-44e1-9d05-a9ef254e899c', 'Pasar Santa', 'Pasar retro yang bertransformasi menjadi pusat komunitas kreatif Jakarta Selatan. Dipenuhi kedai kopi artisan, distro indie, toko vinyl, kuliner unik, dan berbagai produk UMKM lokal yang menjadikannya destinasi wajib kawula muda Jakarta.', 'Jl. Wolter Monginsidi No.99, Kebayoran Baru, Jakarta Selatan', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/b6ffd83d-5a41-4d12-a783-8c12b82958fc.webp', true, '2026-05-20 14:53:40', '2026-05-20 16:34:13', -6.2388416, 106.8171741, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('a7dbc318-b13b-409d-af8e-b0c9d0d4a635', '101a2582-4e74-44d1-b572-059679af8755', 'Kerajinan Payung Geulis Tasikmalaya', 'Payung geulis adalah kerajinan khas Tasikmalaya berupa payung kertas yang dihias dengan lukisan bunga dan motif cantik. Sudah diakui sebagai warisan budaya, kini tersedia dalam berbagai ukuran sebagai dekorasi dan souvenir bernilai seni tinggi.', 'Jl. Panyingkiran, Indihiang, Tasikmalaya', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/a7dbc318-b13b-409d-af8e-b0c9d0d4a635.webp', true, '2026-05-20 14:53:12', '2026-05-20 16:33:13', -7.3041383, 108.2041711, NULL) ON CONFLICT (id) DO NOTHING;
