INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('9ef48a53-07cb-4f73-bd03-08ca5e79d201', 'e5f525d4-c74f-4464-80f4-956f77221f2a', 'Candi Prambanan (Gerbang Klaten)', 'Candi Hindu terbesar di Indonesia dan salah satu Situs Warisan Dunia UNESCO. Kompleks 240 candi dengan Candi Siwa setinggi 47 meter sebagai mahkotanya. Dapat diakses dari Stasiun Klaten dalam 15 menit berkendara.', 'Jl. Raya Solo - Yogyakarta No.16, Prambanan, Klaten', 'Wisata', 4.33, NULL, true, '2026-05-20 14:53:57', '2026-05-20 16:34:32', -7.7123541, 110.6029736, NULL) ON CONFLICT (id) DO NOTHING;
