INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('2591c902-e193-49e6-a3d7-c85f31e89076', 'd475371a-cb92-4314-ba8b-83561f5e6f8a', 'Empal Gentong Krucuk H. Apud', 'Empal gentong autentik Cirebon yang dimasak dalam gentong tanah liat menggunakan kayu bakar. Kuah santan kental gurih berpadu potongan daging sapi dan jeroan empuk. Salah satu kuliner paling ikonik dan wajib coba di Cirebon.', 'Jl. Krucuk, Jagasatru, Cirebon Selatan', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/2591c902-e193-49e6-a3d7-c85f31e89076.webp', true, '2026-05-20 14:52:40', '2026-05-20 16:29:55', -6.7058000, 108.5571000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('14c9485c-ff0f-4e33-b48a-cb08e2e41011', '046f740f-0ecf-4960-8298-6eba206930c7', 'Alun-Alun Merdeka Malang', 'Taman kota bersejarah di jantung Kota Malang yang dikelilingi pohon beringin raksasa. Terdapat kolam bermain anak, area pedagang kaki lima, dan spot foto ikonik. Sore hari dipenuhi warga lokal dan wisatawan yang menikmati suasana kota.', 'Jl. Merdeka Selatan, Kiduldalem, Klojen, Malang', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/14c9485c-ff0f-4e33-b48a-cb08e2e41011.webp', true, '2026-05-20 14:52:36', '2026-05-20 16:29:59', -7.9826131, 112.6308200, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('10150dcd-b4ce-4c56-b3d6-653ba611dc27', 'cd888761-f3b5-4071-acd7-0484892c8c60', 'Taman Bungkul', 'Taman kota terbaik di Asia Tenggara versi PBB yang menjadi ruang publik favorit warga Surabaya. Fasilitas lengkap: jogging track, skate park, wifi gratis, amphiteater, dan playground anak.', 'Jl. Raya Darmo, Wonokromo, Surabaya', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/10150dcd-b4ce-4c56-b3d6-653ba611dc27.webp', true, '2026-05-20 14:52:17', '2026-05-20 16:30:08', -7.2937555, 112.7392066, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('180c7356-6536-4a65-a2da-7f41ac1dccfe', 'da5a1a86-293c-48ae-ac9a-2d3665db70bb', 'Taman Ismail Marzuki', 'Pusat kebudayaan dan seni terbesar di Jakarta yang menampung teater, galeri seni, planetarium, dan berbagai pertunjukan budaya. Setelah direnovasi, TIM menjadi destinasi wisata seni modern yang memadukan tradisi dan kontemporer.', 'Jl. Cikini Raya No.73, Cikini, Jakarta Pusat', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/180c7356-6536-4a65-a2da-7f41ac1dccfe.webp', true, '2026-05-20 14:53:27', '2026-05-20 16:36:08', -6.1891550, 106.8398854, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('367cf2c2-68f3-4350-aea4-24aa840ea65f', 'cd7cf2d0-2237-4770-93e2-a9e23524c8fd', 'Gumuk Pasir Parangkusumo', 'Fenomena alam unik berupa padang pasir mini satu-satunya di Asia Tenggara yang terbentuk dari endapan abu vulkanik Gunung Merapi. Cocok untuk sandboarding, foto kreatif, dan menikmati lanskap yang terasa bukan seperti Indonesia.', 'Parangkusumo, Kretek, Bantul, Daerah Istimewa Yogyakarta', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/367cf2c2-68f3-4350-aea4-24aa840ea65f.webp', true, '2026-05-20 14:54:03', '2026-05-20 16:36:22', -8.0228231, 110.3235393, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('f9d6dfc3-f92b-4d43-aadd-f3a8460408ef', '0d3a0021-8963-404a-be94-bd813a115ddf', 'Taman Suropati Menteng', 'Taman kota bersejarah di jantung kawasan Menteng yang dikelilingi gedung-gedung kolonial Belanda abad ke-20. Spot favorit seniman jalanan, komunitas musik, dan warga Jakarta untuk bersantai di tengah kota.', 'Jl. Taman Suropati, Menteng, Jakarta Pusat', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/f9d6dfc3-f92b-4d43-aadd-f3a8460408ef.webp', true, '2026-05-20 14:54:13', '2026-05-20 16:36:56', -6.1984777, 106.8326379, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('76b683fb-c44a-40ac-879b-b01e4166a505', '23ffd64f-e657-432c-8073-09f7b2b618d7', 'Benteng Heritage Museum', 'Museum sejarah Tangerang yang menempati bangunan Benteng VOC abad ke-18. Koleksinya mencakup artefak sejarah Tangerang, dokumen kolonial, dan benda-benda peninggalan komunitas Tionghoa yang menetap sejak abad ke-17.', 'Jl. Benteng Makasar No.1, Sukasari, Tangerang', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/76b683fb-c44a-40ac-879b-b01e4166a505.webp', true, '2026-05-20 14:53:52', '2026-05-20 16:36:03', -6.1786898, 106.6296439, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('45b55be6-003e-4a17-bdcf-5023dc3b4574', '8e5e5067-8107-4ccd-b084-935353418af8', 'Agrowisata Salak Sikasur', 'Perkebunan salak di kawasan Bawang Batang yang menawarkan wisata petik salak langsung dan pemandangan pegunungan.', 'Bawang, Batang', 'Wisata', 4.10, 'https://cdn.jejakjalur.project-n.site/destinasi/45b55be6-003e-4a17-bdcf-5023dc3b4574.webp', true, '2026-05-22 23:21:38', '2026-05-22 23:21:38', NULL, -7.0270000, 109.8540000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('97c3bc7b-8b42-4e0c-9796-f9f07f7d0bef', 'e88e39b5-2f31-43d8-9580-42bdc036cff9', 'Warung Bu Darum', 'Warung masakan rumahan Jawa Timur autentik sejak 1953. Menu beragam: nasi pecel, rawon, soto Jawa Timur, rames, kare ayam, dan nasi bali. Harga sangat terjangkau dan porsi mengenyangkan, menjadikannya favorit mahasiswa dan pelancong.', 'Jl. PB Sudirman No.42, Jember', 'Kuliner', 4.67, NULL, true, '2026-05-20 14:53:21', '2026-05-20 16:35:06', -8.1647000, 113.7019000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('7598132e-22b3-4a3f-b3d6-859368fe0406', '87b8108a-f5c0-4a2f-b44e-e05c13ed96a4', 'Bundaran Hotel Indonesia', 'Ikon kota Jakarta dengan air mancur dan patung Selamat Datang yang menjadi simbol kebanggaan ibukota, ramai saat Car Free Day.', 'Bundaran HI, Jakarta Pusat', 'Wisata', 4.40, NULL, true, '2026-05-22 23:11:14', '2026-05-22 23:11:14', NULL, -6.1933000, 106.8224000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('a81cfdff-9638-439e-ad5c-1a9881b78634', '83491f38-3ec3-42d2-9673-1366031fa938', 'Lokawisata Baturraden', 'Kawasan wisata alam di lereng Gunung Slamet (ketinggian 640 mdpl) dengan berbagai wahana alam — kolam renang air panas belerang, curug telu, pancuran pitu, dan hutan pinus. Udara sejuk pegunungan dan panorama hutan tropis yang asri.', 'Baturraden, Banyumas, Jawa Tengah', 'Wisata', 4.33, NULL, true, '2026-05-20 14:55:31', '2026-05-20 16:39:39', -7.3090412, 109.2290459, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('1a5fc1eb-450b-4eb8-ab0a-a42a1007e631', 'a8104542-ad6b-4e83-bd6f-857fa32194d0', 'Klenteng Sam Poo Kong', 'Tempat ibadah dan wisata sejarah terbesar di Semarang yang didirikan untuk mengenang Laksamana Zheng He dari Tiongkok. Arsitektur Tiongkok merah megah berpadu taman hijau luas, menarik wisatawan dari seluruh Indonesia.', 'Jl. Simongan No.129, Semarang Barat', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/1a5fc1eb-450b-4eb8-ab0a-a42a1007e631.webp', true, '2026-05-20 14:52:25', '2026-05-20 16:30:11', -6.9943053, 110.3985962, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('92132a86-0742-4db5-9d7c-2edc8659e2fb', '83491f38-3ec3-42d2-9673-1366031fa938', 'Mendoan Banyumas', 'Tempe mendoan khas Banyumas — tempe tipis yang digoreng setengah matang dengan tepung berbumbu khas hingga bagian luar renyah dan dalam tetap lembut. Warisan kuliner Banyumas yang telah ditetapkan sebagai Warisan Budaya Takbenda Indonesia.', 'Pasar Wage, Purwokerto, Banyumas', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/92132a86-0742-4db5-9d7c-2edc8659e2fb.webp', true, '2026-05-20 14:55:34', '2026-05-20 16:40:31', -7.4263925, 109.2493942, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('188954c9-9df9-4bb7-af5b-7010c6bb0980', '967c22a6-cd52-4a48-a0ad-583de9ef4832', 'Museum Batik Danar Hadi', 'Museum yang memamerkan ribuan koleksi batik bersejarah dari berbagai daerah Indonesia dengan galeri informatif dan toko batik premium.', 'Jl. Slamet Riyadi No.261, Surakarta', 'Wisata', 4.30, 'https://cdn.jejakjalur.project-n.site/destinasi/188954c9-9df9-4bb7-af5b-7010c6bb0980.webp', true, '2026-05-22 23:11:14', '2026-05-22 23:11:14', NULL, -7.5654000, 110.8231000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('c82910e8-ed48-4856-ac99-443c0296eaf1', 'cd7cf2d0-2237-4770-93e2-a9e23524c8fd', 'Pantai Parangtritis', 'Pantai paling terkenal di Yogyakarta dengan pasir hitam vulkanik dan ombak besar Samudra Hindia. Legenda Nyi Roro Kidul membuat pantai ini semakin mistis. Tersedia wisata delman, sandboarding di gumuk pasir, dan sunset yang menakjubkan.', 'Parangtritis, Kretek, Bantul, Daerah Istimewa Yogyakarta', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/c82910e8-ed48-4856-ac99-443c0296eaf1.webp', true, '2026-05-20 14:54:01', '2026-05-20 16:44:42', -8.0031654, 110.3166865, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('8ae1e844-3120-4764-b58e-0f6db06b2f24', '046f740f-0ecf-4960-8298-6eba206930c7', 'Rawon Rampal', 'Rawon legendaris Malang sejak 1957 yang selalu ramai. Kuah hitam pekat dari kluwek pilihan, gurih dan kaya rempah, disajikan dengan daging sapi empuk berukuran besar, tauge segar, dan kerupuk udang. Ikon kuliner kota Malang.', 'Jl. Panglima Sudirman No.71A, Blimbing, Malang', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/8ae1e844-3120-4764-b58e-0f6db06b2f24.webp', true, '2026-05-20 14:52:36', '2026-05-20 16:31:26', -7.9778000, 112.6378000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('2c9bc6b4-4cb4-4d0c-9cbe-63514b8bf8b4', '962460e6-c222-4725-a275-1e7a8846019f', 'Pusat Kuliner Pratistha Hasta', 'Pusat jajanan kuliner khas Banyumas yang dikenal sebagai Pasar Minggu. Ratusan penjual menawarkan aneka makanan lokal: sroto Sokaraja, nopia, mendoan, tempe kripik, hingga berbagai minuman tradisional khas Banyumas.', 'Jl. Jend. Gatot Subroto, Purwokerto Selatan', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/2c9bc6b4-4cb4-4d0c-9cbe-63514b8bf8b4.webp', true, '2026-05-20 14:52:49', '2026-05-20 16:31:45', -7.4378000, 109.2253000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('fef86215-1ab2-46e9-ab1e-8ab757a23912', '046f740f-0ecf-4960-8298-6eba206930c7', 'Bakso Cak Toha', 'Bakso paling terkenal di kawasan Malang kota, hanya 120 meter dari stasiun. Tersedia bakso besar, bakso iga, bakso goreng, siomay, dan gorengan. Kuah kaldu sapi bening yang gurih dan porsi melimpah menjadi daya tarik utamanya.', 'Jl. Trunojoyo No.80, Klojen, Malang', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/fef86215-1ab2-46e9-ab1e-8ab757a23912.webp', true, '2026-05-20 14:52:37', '2026-05-20 16:31:49', -7.9767826, 112.6369053, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('309c580d-1ae6-4e86-8807-1f39db160059', '98d07c34-4170-4f9e-b097-5356b571ac7b', 'Mie Kocok Haji Maman', 'Mie kocok asli Bandung dengan kuah kaldu sapi bening nan gurih. Topping kikil sapi kenyal, tauge segar, dan bakso membuat sajian ini jadi kuliner favorit di kawasan Kiaracondong.', 'Jl. Jend. Ahmad Yani No.10, Kiaracondong, Bandung', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/309c580d-1ae6-4e86-8807-1f39db160059.webp', true, '2026-05-20 14:52:04', '2026-05-20 16:28:26', -6.9244000, 107.6438000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('3b0fc063-66b6-4242-810b-1db8038491cd', '25c4d072-5661-4cf6-9225-9d99660339f9', 'Tahu Kuning Kediri Kak Ana', 'Tahu kuning khas Kediri yang sudah terkenal ke seluruh Indonesia. Terbuat dari kedelai pilihan dan diberi pewarna alami kunyit, menghasilkan tahu berwarna kuning dengan tekstur kenyal dan rasa gurih khas. Tersedia dalam kemasan siap kirim.', 'Jl. Pattimura No.89, Kota Kediri', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/3b0fc063-66b6-4242-810b-1db8038491cd.webp', true, '2026-05-20 14:52:57', '2026-05-20 16:32:06', -7.8217000, 112.0114000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('82d2b020-558a-4a61-b084-eb5a7dafc1f9', '79993c21-20b5-4f61-af26-1a37dc95c7ec', 'Desa Wisata Tembi', 'Desa wisata budaya yang mempertahankan tradisi Jawa. Pengunjung dapat menginap di rumah joglo, belajar membatik, bermain gamelan, dan menikmati pertunjukan seni tradisional Jawa.', 'Jl. Parangtritis KM 8.4, Tembi, Bantul, Yogyakarta', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/82d2b020-558a-4a61-b084-eb5a7dafc1f9.webp', true, '2026-05-20 14:52:15', '2026-05-20 16:31:16', -7.7894000, 110.3789000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('35b503eb-d705-41a0-9e3d-feebe51eb9d0', '9e750b4a-1089-441f-a9ec-864bb2ce9b63', 'Pantai Karangsong Indramayu', 'Pantai dan kawasan konservasi mangrove di Indramayu dengan hutan bakau seluas ratusan hektare. Spot bird watching, susur mangrove dengan perahu, dan menikmati hasil laut segar langsung dari nelayan di tempat pelelangan ikan.', 'Karangsong, Indramayu, Jawa Barat', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/35b503eb-d705-41a0-9e3d-feebe51eb9d0.webp', true, '2026-05-20 14:54:50', '2026-05-20 16:38:52', -6.3078332, 108.3558589, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('09a99332-f24a-4525-8c15-828415071ab2', '9b9b5c27-b14c-4d1d-a647-faaccd6a76ed', 'Oncom Cimahi', 'Oncom merah khas Cimahi yang menjadi bahan baku berbagai masakan Sunda autentik. Pabrik oncom tradisional di Cimahi memproduksi oncom berkualitas dari kedelai pilihan yang dijual langsung dan menjadi oleh-oleh khas daerah.', 'Pasar Antri Cimahi, Cimahi Tengah', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/09a99332-f24a-4525-8c15-828415071ab2.webp', true, '2026-05-20 14:54:34', '2026-05-20 16:39:16', -6.8736000, 107.5419000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('edd82708-caaf-4e6a-b76f-92f617e32dc8', '9077394d-f0e0-4bcf-bd22-2dfefeaa1260', 'Pantai Karangbolong Kebumen', 'Pantai dengan formasi batu karang berlubang (bolong) yang ikonik, membentuk gua alami tempat air laut masuk dan menciptakan kolam alam yang indah. Di sekitarnya terdapat sarang burung walet alami yang sudah dipanen masyarakat sejak ratusan tahun.', 'Karangbolong, Buayan, Kebumen', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/edd82708-caaf-4e6a-b76f-92f617e32dc8.webp', true, '2026-05-20 14:55:28', '2026-05-20 16:39:49', -7.6503079, 109.4924330, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('e53e1f80-3488-4257-b959-01124ed213ec', '1f99f2c9-8eac-4660-8c1e-da99758931ed', 'Pasar Cimindi', 'Pasar tradisional yang ramai di Cimindi dengan berbagai pilihan bahan makanan segar dan produk kebutuhan harian masyarakat sekitar.', 'Jl. Cimindi, Cimahi, Bandung', 'UMKM', 3.70, NULL, true, '2026-05-22 23:21:38', '2026-05-22 23:21:38', NULL, -6.8950000, 107.5440000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('441ab35c-10a2-4039-82ec-1be4ff0b5032', 'f9d81219-a015-4615-b82f-fd5e566a352a', 'Kayangan Api (Api Abadi Bojonegoro)', 'Api abadi yang menyala tanpa henti dari dalam tanah akibat semburan gas alam sejak zaman Kerajaan Majapahit. Konon menjadi tempat pertapaan Empu Supa pembuat pusaka kerajaan. Fenomena geologi langka yang berada di tengah kawasan hutan jati Bojonegoro.', 'Sendangharjo, Ngasem, Bojonegoro', 'Wisata', 4.33, NULL, true, '2026-05-20 14:55:52', '2026-05-20 16:41:19', -7.2614565, 111.7720067, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('2bbf4a77-2ca1-4dc4-ae34-eae3f7ac0965', 'c04e8484-9604-4c3b-a42f-047005ab6bfa', 'Pasar Pesanggaran', 'Pasar tradisional di Pesanggaran yang menjual produk pertanian dan ikan dari kawasan pesisir selatan Banyuwangi.', 'Pesanggaran, Banyuwangi', 'UMKM', 3.50, NULL, true, '2026-05-22 23:21:38', '2026-05-22 23:21:38', NULL, -8.3750000, 114.0580000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('f1997100-0e2c-4456-890e-8b151afe6a29', 'dae14468-6806-4625-83a2-9b7701b1bb5f', 'Waduk Cirata Cipatat', 'Sisi Cipatat dari Waduk Cirata menawarkan pemandangan danau biru yang luas dengan latar pegunungan yang cocok untuk piknik dan fotografi.', 'Cipatat, Bandung Barat', 'Wisata', 4.00, NULL, true, '2026-05-22 23:21:38', '2026-05-22 23:21:38', NULL, -6.8075000, 107.3500000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('0e6ed096-c488-4487-a47a-464b57086b14', '13f3ede0-2381-469e-9e61-b57afc000929', 'Plaza Senayan', 'Mal premium bergaya Eropa yang menawarkan pengalaman belanja eksklusif dengan suasana elegan dan deretan butik internasional.', 'Jl. Asia Afrika No.8, Jakarta Pusat', 'UMKM', 4.40, NULL, true, '2026-05-22 23:11:14', '2026-05-22 23:11:14', NULL, -6.2249000, 106.7999000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('0fc3c53c-c96d-4da4-86d1-b5d2386e9286', 'c3596b44-8f81-46cb-a90f-67929c4a1782', 'Grand Metropolitan Mall Bekasi', 'Pusat perbelanjaan modern terbesar di Bekasi Barat dengan ratusan tenant fashion, restoran, dan bioskop yang lengkap.', 'Jl. KH Noer Ali, Bekasi', 'UMKM', 4.20, NULL, true, '2026-05-22 23:41:49', '2026-05-22 23:41:49', NULL, -6.2282000, 106.9989000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('85cecc4b-e91f-46d1-adbb-8c9cbbdf8c3e', '9077394d-f0e0-4bcf-bd22-2dfefeaa1260', 'Benteng Van der Wijck', 'Benteng militer berbentuk segi delapan peninggalan Belanda (1827) yang kini dijadikan kawasan wisata sejarah dan hiburan. Uniknya, di dalam benteng terdapat stasiun kereta mini yang mengelilingi kompleks serta museum tentang sejarah militer Hindia Belanda.', 'Gombong, Kebumen, Jawa Tengah', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/85cecc4b-e91f-46d1-adbb-8c9cbbdf8c3e.webp', true, '2026-05-20 14:55:26', '2026-05-20 16:39:47', -7.6108578, 109.5066911, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('c5813e64-22ab-4901-aba8-ede8805413c2', '7a56e769-d853-4d95-b830-676ae09b1e77', 'Pindang Tetel Pak Darsono', 'Pindang tetel adalah masakan khas Pekalongan yang jarang ditemukan di kota lain — potongan daging sapi dimasak dalam bumbu hitam kecap yang kaya rempah, pedas, dan sangat gurih. Cocok disantap dengan nasi hangat dan kerupuk.', 'Jl. Wahid Hasyim No.44, Pekalongan Timur', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/c5813e64-22ab-4901-aba8-ede8805413c2.webp', true, '2026-05-20 14:53:10', '2026-05-20 16:32:28', -6.8881000, 109.6731000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('9e569e9a-bafe-415a-ad5b-7f07fa40afbd', '759ce88e-d229-471a-b8a0-2cf0e2ff69bf', 'Sate Blengong Tegal Bu Hj. Darmi', 'Sate blengong adalah kuliner langka khas Tegal — menggunakan daging blengong (persilangan itik dan mentok) yang empuk dengan tekstur unik. Dibakar dengan bumbu kecap khas, aromanya harum dan rasanya lebih gurih dibanding sate ayam biasa.', 'Jl. Setiabudi No.22, Tegal Selatan', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/9e569e9a-bafe-415a-ad5b-7f07fa40afbd.webp', true, '2026-05-20 14:53:07', '2026-05-20 16:32:41', -6.8689000, 109.1333000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('2262f20c-948c-46ff-95c2-acf2edf048a1', 'c28816de-51ce-40b1-90c2-76e4fa290a67', 'Telaga Sarangan', 'Danau alami terluas di Jawa Timur di ketinggian 1.200 mdpl di kaki Gunung Lawu. Pemandangan danau biru dikelilingi pegunungan hijau dengan suhu 15-20°C yang sejuk. Tersedia perahu motor, berkuda mengelilingi danau, dan berbagai kuliner ikan bakar.', 'Sarangan, Plaosan, Magetan, Jawa Timur', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/2262f20c-948c-46ff-95c2-acf2edf048a1.webp', true, '2026-05-20 14:56:03', '2026-05-20 16:42:00', -7.6773801, 111.2178662, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('bdaf21ca-e1fa-4af7-b94b-ce8a9a63d463', '9077394d-f0e0-4bcf-bd22-2dfefeaa1260', 'Lanting Kebumen', 'Camilan tradisional khas Kebumen berbahan singkong yang digoreng hingga renyah dalam bentuk lingkaran atau spiral. UMKM lanting Kebumen tersebar di berbagai kecamatan dengan harga terjangkau, menjadikannya oleh-oleh paling populer dari Kebumen.', 'Sentra Lanting, Gombong, Kebumen', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/bdaf21ca-e1fa-4af7-b94b-ce8a9a63d463.webp', true, '2026-05-20 14:55:28', '2026-05-20 16:40:34', -7.7786617, 109.8045838, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('53c5bed5-5953-4fa9-b900-69a04890c582', 'f75823be-9f39-4b0b-a0fb-10912b313a3e', 'Candi Pari Sidoarjo', 'Candi Hindu peninggalan Majapahit abad ke-14 yang terbuat dari bata merah dengan arsitektur yang masih terawat baik. Satu-satunya candi di Sidoarjo yang berdiri kokoh di tengah permukiman, menjadi bukti kejayaan Kerajaan Majapahit di delta Sungai Brantas.', 'Candi, Porong, Sidoarjo', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/53c5bed5-5953-4fa9-b900-69a04890c582.webp', true, '2026-05-20 14:55:45', '2026-05-20 16:40:51', -7.5161068, 112.6833564, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('98fa2ebe-1bc0-4f03-86c5-d197e8fcbad5', '79993c21-20b5-4f61-af26-1a37dc95c7ec', 'Pasar Beringharjo', 'Pasar tradisional terbesar dan tertua di Yogyakarta. Pusat perbelanjaan batik, kerajinan tangan, rempah-rempah, dan berbagai produk UMKM lokal yang menjadi bagian dari heritage Kraton.', 'Jl. Margo Mulyo No.16, Ngupasan, Yogyakarta', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/98fa2ebe-1bc0-4f03-86c5-d197e8fcbad5.webp', true, '2026-05-20 14:52:13', '2026-05-20 16:31:10', -7.7985626, 110.3651093, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('42304d20-1057-4446-bc76-8bbb5befe24f', '35d18352-24e3-404a-8128-2e286537dd2f', 'Taman Safari Prigen', 'Taman safari terbesar kedua di Indonesia di lereng Gunung Arjuno (ketinggian 800-1.400 mdpl). Lebih dari 2.500 satwa dari berbagai penjuru dunia dapat dilihat dari jarak dekat di habitat semi-alami. Wahana safari malam dan berbagai atraksi satwa tersedia.', 'Prigen, Pasuruan, Jawa Timur', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/42304d20-1057-4446-bc76-8bbb5befe24f.webp', true, '2026-05-20 14:56:05', '2026-05-20 16:42:22', -7.6805545, 112.6406232, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('a3cc1baf-3c6b-468c-bf62-cb664d4fd342', '7c6aa826-60b4-41a3-ac80-cdcd85dce3f8', 'Taman Sari Water Castle', 'Bekas taman kerajaan Kesultanan Yogyakarta yang dibangun pada abad ke-18. Kompleks ini mencakup kolam pemandian kerajaan, terowongan bawah tanah, dan arsitektur Jawa-Portugis yang memukau.', 'Jl. Taman, Patehan, Kraton, Yogyakarta', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/a3cc1baf-3c6b-468c-bf62-cb664d4fd342.webp', true, '2026-05-20 14:52:08', '2026-05-20 16:43:23', -7.8099550, 110.3608397, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('d9b8a19e-8f40-4594-85d1-583c67ccca04', '531f81c5-ec85-4dc3-bdeb-efb5d565abbf', 'Danau Kenanga UI', 'Danau buatan nan indah di dalam kampus Universitas Indonesia yang dikelilingi hutan tropis hijau. Spot foto favorit warga Depok dengan perahu dayung, pohon-pohon besar berusia puluhan tahun, dan suasana alam yang menenangkan.', 'Kampus UI, Pondok Cina, Beji, Depok', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/d9b8a19e-8f40-4594-85d1-583c67ccca04.webp', true, '2026-05-20 14:53:48', '2026-05-20 16:43:02', -6.3611000, 106.8316000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('d2108707-6541-402c-abd9-3635734c9a8d', '37bb54a6-88d6-423e-b28f-6647f5910217', 'Lanting Cilacap', 'Kerupuk lanting khas Cilacap berbahan singkong dengan bentuk angka delapan yang renyah dan gurih. Diproduksi oleh ratusan UMKM rumahan di Cilacap dengan berbagai varian rasa pedas dan original, sudah dikenal hingga mancanegara.', 'Sentra Lanting, Jl. Raya Cilacap', 'UMKM', 4.33, NULL, true, '2026-05-20 14:55:37', '2026-05-20 16:40:14', -7.7297000, 109.0094000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('45af4ff9-5109-438f-b860-45a7a5fa6493', '586945fe-8ede-42b6-b57f-5c98be9af564', 'Pasar Cikalong', 'Pasar tradisional yang melayani kebutuhan warga Cikalongwetan dengan sayuran segar dari kebun setempat dan ikan dari waduk.', 'Cikalongwetan, Bandung Barat', 'UMKM', 3.60, NULL, true, '2026-05-22 23:21:38', '2026-05-22 23:21:38', NULL, -6.7510000, 107.4020000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('f9109f27-3263-491f-b877-f0e644697fff', '82d1b189-c47b-4521-967b-de2b916acfd9', 'Sate Ayam Ponorogo Pak Karwo', 'Sate ayam Ponorogo khas yang terkenal di Madiun — daging ayam muda bertekstur lembut dimarinasi bumbu kuning, dibakar sempurna, dan disajikan dengan bumbu kacang manis gurih kental. Berbeda dengan sate biasa, ini menggunakan potongan daging tanpa tulang.', 'Jl. Pahlawan No.13, Madiun', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/f9109f27-3263-491f-b877-f0e644697fff.webp', true, '2026-05-20 14:53:04', '2026-05-20 16:33:37', -7.6300000, 111.5292000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('667da280-7fa9-4a31-b855-fc0d70181429', '1c3f1ee8-4438-4779-a487-ba8774e4ead8', 'Kerajinan Anyaman Rotan Banjar', 'Sentra kerajinan anyaman rotan dan bambu khas Banjar yang sudah terkenal hingga mancanegara. Berbagai produk fungsional dan dekoratif: keranjang, tas, kursi, dan perabot rumah tangga tersedia langsung dari pengrajin dengan harga bersahabat.', 'Desa Mekarsari, Pataruman, Banjar', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/667da280-7fa9-4a31-b855-fc0d70181429.webp', true, '2026-05-20 14:53:17', '2026-05-20 16:33:43', -7.4072194, 108.5282920, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('9216e838-fcc4-4c7c-a49d-ec09cbfbcbdf', '759ce88e-d229-471a-b8a0-2cf0e2ff69bf', 'Batik Tegalan Tobal', 'Pusat batik khas Tegal dengan motif yang berbeda dari batik Jawa pada umumnya — lebih berani dalam warna dan motif geometris kontemporer. Bisa memesan custom batik sesuai selera dan belajar membatik langsung dari pengrajin.', 'Jl. Sumbodro No.15, Tegal', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/9216e838-fcc4-4c7c-a49d-ec09cbfbcbdf.webp', true, '2026-05-20 14:53:07', '2026-05-20 16:33:54', -6.8689000, 109.1333000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('2fa9f901-d25d-4d12-9400-f4e3bad60268', '25c4d072-5661-4cf6-9225-9d99660339f9', 'Soto Ayam Kampung Kediri Pak Sabar', 'Soto ayam kampung khas Kediri dengan kuah bening ringan dan wangi, berisi suwiran daging ayam kampung, tauge, dan soun. Disantap dengan nasi atau lontong, tambah kerupuk dan sambal — sarapan paling dicari warga Kediri.', 'Jl. Dhoho No.65, Kota Kediri', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/2fa9f901-d25d-4d12-9400-f4e3bad60268.webp', true, '2026-05-20 14:52:58', '2026-05-20 16:34:01', -7.8217000, 112.0114000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('cf60b3ab-8ca3-4d00-bdd1-cbda19d88ce7', 'f30610a2-7395-4572-bb4b-af49049cb452', 'Museum Fatahillah (Museum Sejarah Jakarta)', 'Museum ikonik di jantung Kota Tua Jakarta yang menempati gedung Balai Kota VOC abad ke-17. Koleksinya meliputi furnitur kolonial, prasasti, meriam Si Jagur, dan sel penjara bawah tanah yang legendaris.', 'Jl. Taman Fatahillah No.1, Pinangsia, Tamansari, Jakarta Barat', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/cf60b3ab-8ca3-4d00-bdd1-cbda19d88ce7.webp', true, '2026-05-20 14:53:31', '2026-05-20 16:42:47', -6.1378000, 106.8145000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('e636ca76-de2d-49ea-9712-46e09284b0d2', 'ec72e8d2-69be-4346-ba36-d870d1fe8ae5', 'Situs Trowulan (Ibu Kota Majapahit)', 'Kawasan arkeologi seluas 100 km² yang diyakini sebagai bekas ibu kota Kerajaan Majapahit (abad ke-13-16). Lebih dari 100 situs tersebar di sini — Candi Brahu, Candi Bajang Ratu, Kolam Segaran, Gapura Wringinlawang, dan Museum Trowulan.', 'Trowulan, Mojokerto, Jawa Timur', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/e636ca76-de2d-49ea-9712-46e09284b0d2.webp', true, '2026-05-20 14:55:47', '2026-05-20 16:46:21', -7.5328016, 112.4053690, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('a3786640-659c-407e-a610-d2fbb763847f', 'b1427a4f-9c11-45c4-af51-ca83a539e18d', 'Bendungan Darma', 'Bendungan besar di Kuningan yang menciptakan danau waduk biru di antara perbukitan hijau untuk wisata perahu dan pemancingan.', 'Kuningan', 'Wisata', 4.00, NULL, true, '2026-05-22 23:21:38', '2026-05-22 23:21:38', NULL, -6.9810000, 108.4670000, NULL) ON CONFLICT (id) DO NOTHING;
