INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('f57654a1-98c4-48b3-b73b-6527ac51ed7a', '87d916fe-4fa3-4e02-b852-cf6e369ee56e', 'Ayam Lodho Tulungagung', 'Masakan khas Tulungagung berupa ayam kampung yang dibakar lalu dimasak dalam kuah santan kuning kental dengan rempah-rempah yang kuat. Cita rasa yang gurih, sedikit pedas, dan kaya rempah membuat Ayam Lodho menjadi kuliner ikonik Tulungagung.', 'Jl. WR. Supratman, Tulungagung', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/f57654a1-98c4-48b3-b73b-6527ac51ed7a.webp', true, '2026-05-20 14:56:15', '2026-05-20 16:42:17', -8.0653000, 111.9019000, NULL) ON CONFLICT (id) DO NOTHING;
