INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('ad907d06-2d02-47bb-b8ef-581f999a2416', 'e88e39b5-2f31-43d8-9580-42bdc036cff9', 'Suwar-Suwir Jember Bu Mie', 'Oleh-oleh khas Jember yang paling dicari — suwar-suwir adalah permen kenyal berbahan dasar tape singkong pilihan dengan berbagai varian rasa dan warna. Sudah menjadi ikon kuliner Jember yang wajib dibawa pulang setiap wisatawan.', 'Jl. Hayam Wuruk No.11, Jember', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/ad907d06-2d02-47bb-b8ef-581f999a2416.webp', true, '2026-05-20 14:53:20', '2026-05-20 16:44:20', -8.1647000, 113.7019000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('9d4a9060-7896-4b17-ad8a-8d171f20c0f0', 'a48769bb-9c9b-40f9-a0ef-3d761acd42ec', 'Wisata Religi Masjid Agung Batang', 'Masjid agung bersejarah di pusat kota Batang dengan arsitektur tradisional Jawa dan menjadi pusat kegiatan keagamaan masyarakat.', 'Batang Kota', 'Wisata', 4.00, 'https://cdn.jejakjalur.project-n.site/destinasi/9d4a9060-7896-4b17-ad8a-8d171f20c0f0.webp', true, '2026-05-22 23:21:38', '2026-05-22 23:21:38', NULL, -6.9038000, 109.7374000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('e5f6cef7-cffe-4f5d-8605-c57df9b0ccbe', '90516e78-cfbe-44e1-9d05-a9ef254e899c', 'Taman Langsat', 'Taman kota hijau dan asri di Kebayoran Baru yang menjadi oasis di tengah hiruk pikuk Jakarta Selatan. Area favorit warga untuk jogging, piknik, dan bersantai dengan koleksi pepohonan rindang dan fasilitas olahraga yang memadai.', 'Jl. Barito II, Kramat Pela, Kebayoran Baru, Jakarta Selatan', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/e5f6cef7-cffe-4f5d-8605-c57df9b0ccbe.webp', true, '2026-05-20 14:53:42', '2026-05-20 16:35:20', -6.2462425, 106.7945195, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('22012dd9-d94f-46fb-9ffa-e5a5bcb24d9e', '30d391c5-5ab3-4d4c-a39c-505a7bb10129', 'Alun-Alun Kota Bekasi', 'Ruang terbuka hijau di pusat Kota Bekasi yang menjadi titik kumpul warga. Dilengkapi area jogging, pertunjukan seni, dan jajanan kaki lima dengan berbagai kuliner lokal khas Bekasi yang ramai di sore dan malam hari.', 'Jl. IR. H. Juanda, Margahayu, Bekasi Timur, Kota Bekasi', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/22012dd9-d94f-46fb-9ffa-e5a5bcb24d9e.webp', true, '2026-05-20 14:53:47', '2026-05-20 16:34:57', -6.2418689, 106.9998988, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('add38810-68f8-4317-83f2-23f22842a72a', 'd475371a-cb92-4314-ba8b-83561f5e6f8a', 'Masjid Merah Panjunan', 'Masjid bersejarah berusia lebih dari 500 tahun yang dibangun oleh Sunan Gunung Jati. Arsitekturnya unik memadukan gaya Arab, Tiongkok, dan Jawa dengan dinding bata merah khas yang membuatnya berbeda dari masjid lain di Indonesia.', 'Jl. Panjunan, Panjunan, Lemahwungkuk, Cirebon', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/add38810-68f8-4317-83f2-23f22842a72a.webp', true, '2026-05-20 14:52:44', '2026-05-20 16:43:46', -6.7182486, 108.5666355, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('5c089ec8-08ff-4161-97c5-436171a88449', '79993c21-20b5-4f61-af26-1a37dc95c7ec', 'Candi Prambanan', 'Kompleks candi Hindu terbesar di Indonesia dan warisan dunia UNESCO. Dibangun pada abad ke-9, candi utama Trimurti (Brahma, Wisnu, Siwa) menjulang setinggi 47 meter.', 'Jl. Raya Solo - Yogyakarta No.16, Prambanan, Sleman', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/5c089ec8-08ff-4161-97c5-436171a88449.webp', true, '2026-05-20 14:52:11', '2026-05-20 16:44:01', -7.7522269, 110.4915331, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('a554d60d-95cb-44af-a9da-65a6cfb850ea', '3a794bc8-9f56-482a-af70-c55e31a858c1', 'Taman Mini Indonesia Indah (TMII)', 'Taman wisata bertema kebudayaan Indonesia dengan 33 anjungan provinsi, museum, danau miniatur kepulauan Indonesia, dan berbagai wahana edukasi. Destinasi keluarga terpopuler di Jakarta Timur yang menyajikan kekayaan budaya Nusantara.', 'Jl. Raya Taman Mini, Cipayung, Jakarta Timur', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/a554d60d-95cb-44af-a9da-65a6cfb850ea.webp', true, '2026-05-20 14:54:21', '2026-05-20 16:45:18', -6.3043017, 106.9062417, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('9565bd48-9c4e-4f61-8361-154f51363002', '64515b88-6230-43d2-bb24-115b36891471', 'Sate Ayam Blora', 'Sate ayam khas Blora dengan ukuran tusukan yang lebih kecil namun lebih banyak per porsi. Menggunakan ayam kampung pilihan dengan bumbu kacang spesial yang lebih cair dan sedikit manis, disajikan dengan lontong dan bawang goreng. Wajib dicoba saat transit di Blora.', 'Alun-alun Blora, Jl. A. Yani, Blora', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/9565bd48-9c4e-4f61-8361-154f51363002.webp', true, '2026-05-20 14:55:15', '2026-05-20 16:43:53', -7.1456000, 111.5944000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('8fb3e334-0fce-4cf3-ab9d-111235ed6cc9', '58ca1eda-c5a6-4894-aa52-fd0c18feb280', 'Pantai Bentar Probolinggo', 'Pantai wisata dengan pemandangan laut dan pulau kecil di lepas pantai. Wisata snorkeling, diving, dan memancing tersedia di perairan Bentar. Di dekat pantai terdapat sentra penjualan mangga Manalagi dan Arumanis khas Probolinggo yang sangat manis.', 'Gending, Probolinggo, Jawa Timur', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/8fb3e334-0fce-4cf3-ab9d-111235ed6cc9.webp', true, '2026-05-20 14:56:09', '2026-05-20 16:46:02', -7.7921711, 113.3089448, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('51825217-998d-4983-984c-e9611ee515a1', '8d1efe9a-5863-448e-9492-6aa2ef47a6b9', 'Sungai Serayu Kebasen', 'Kawasan tepi Sungai Serayu di Kebasen yang menawarkan wisata arung jeram dan pemandangan alam pedesaan yang asri.', 'Kebasen, Banyumas', 'Wisata', 3.90, 'https://cdn.jejakjalur.project-n.site/destinasi/51825217-998d-4983-984c-e9611ee515a1.webp', true, '2026-05-22 23:21:38', '2026-05-22 23:21:38', NULL, -7.5310000, 109.2010000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('fa7c0b55-ee30-4f8b-9afa-3d279e620264', '50c3df44-987e-4e6e-bf1b-c4db867fcb08', 'Taman Anggrek Indonesia Permai', 'Salah satu pusat perbelanjaan terbesar di Jakarta Barat dengan konsep taman anggrek. Memiliki ratusan tenant fashion, kuliner, dan hiburan, serta roof garden dengan koleksi tanaman anggrek yang indah.', 'Jl. Letjen S. Parman Kav. 21, Tanjung Duren Selatan, Jakarta Barat', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/fa7c0b55-ee30-4f8b-9afa-3d279e620264.webp', true, '2026-05-20 14:53:38', '2026-05-20 16:42:56', -6.1620350, 106.7896101, NULL) ON CONFLICT (id) DO NOTHING;
