INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('c6853605-1998-4a5f-864e-0f963e31029d', 'c0fada2e-9396-4db6-9c0c-3ccdb7eaa72f', 'Pusat Grosir Tanah Abang', 'Pasar tekstil dan fashion terbesar di Asia Tenggara dengan lebih dari 15.000 kios. Menawarkan berbagai produk fashion, kain batik, aksesoris, dan perlengkapan busana dengan harga grosir yang sangat terjangkau.', 'Jl. KH. Wahid Hasyim, Tanah Abang, Jakarta Pusat', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/c6853605-1998-4a5f-864e-0f963e31029d.webp', true, '2026-05-20 14:53:37', '2026-05-20 16:35:19', -6.1873357, 106.8163688, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('20984768-2a47-4fdb-ade4-6b3db120fdc7', 'e5f525d4-c74f-4464-80f4-956f77221f2a', 'Warung Soto Klaten Pak Marto', 'Soto ayam khas Klaten dengan kuah bening segar yang kaya rempah kunyit dan sereh. Menggunakan ayam kampung pilihan, disajikan dengan nasi putih, krupuk, dan sambal tomat segar. Sarapan favorit warga Klaten sejak tiga generasi.', 'Jl. Pemuda No.45, Klaten Tengah, Klaten', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/20984768-2a47-4fdb-ade4-6b3db120fdc7.webp', true, '2026-05-20 14:53:57', '2026-05-20 16:36:00', -7.7123541, 110.6029736, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('21db6134-aff7-429d-b484-54afe7b4a995', 'e88e39b5-2f31-43d8-9580-42bdc036cff9', 'Alun-Alun Jember', 'Jantung kota Jember yang dikelilingi pohon rindang dan gedung bersejarah colonial. Menjadi pusat kegiatan warga, festival seni, dan Car Free Day. Di malam hari ramai dengan pedagang kaki lima yang menjual berbagai kuliner khas Jember.', 'Jl. Supriyadi, Kaliwates, Jember', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/21db6134-aff7-429d-b484-54afe7b4a995.webp', true, '2026-05-20 14:53:19', '2026-05-20 16:33:01', -8.1689005, 113.7021649, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('eb8bb150-9de4-4e16-8eca-80ffb737abf9', '33168bd1-e746-4380-a5f4-cfd8eab7b42d', 'Blok M Square', 'Pusat perbelanjaan underground ikonik Blok M yang menggabungkan konsep mall modern dengan bazaar tradisional. Dikenal sebagai surga belanja fashion murah, aksesoris, dan berbagai produk lokal dengan harga terjangkau.', 'Jl. Bulungan No.76, Kramat Pela, Kebayoran Baru, Jakarta Selatan', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/eb8bb150-9de4-4e16-8eca-80ffb737abf9.webp', true, '2026-05-20 14:53:42', '2026-05-20 16:34:08', -6.2445743, 106.8006164, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('7bbb97a5-9f47-4026-956d-1295e67025bb', '498c089b-8e3f-48c9-a89d-53e3300c357d', 'Universitas Pasundan', 'Universitas Pasundan (Unpas) kampus Setiabudi, salah satu perguruan tinggi swasta terkemuka di Bandung. Berlokasi di Jl. Dr. Setiabudi, kampus ini memiliki suasana asri dan menjadi pusat pendidikan seni, teknik, dan ilmu sosial.', 'Jl. Dr. Setiabudi No.193, Gegerkalong, Kec. Sukasari, Kota Bandung, Jawa Barat 40153', 'Wisata', 0.00, 'https://cdn.jejakjalur.project-n.site/destinasi/7bbb97a5-9f47-4026-956d-1295e67025bb.webp', true, '2026-05-23 22:32:26', '2026-05-23 22:32:26', NULL, -6.8693000, 107.5965000, '967afd96-15d8-4356-8550-2023829768af') ON CONFLICT (id) DO NOTHING;
