INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('543f2543-7cf5-422f-94b0-b7496117ca76', '62fb2426-946c-4e47-9e2b-2f362675d43c', 'Rujak Cingur Ahmad Jais', 'Rujak cingur legendaris khas Surabaya yang menggunakan cingur (hidung sapi) sebagai bahan utama. Bumbu petis hitam pekat dengan berbagai sayuran dan lontong menjadi sajian yang wajib dicoba.', 'Jl. Ahmad Jais No.40, Sawahan, Surabaya', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/543f2543-7cf5-422f-94b0-b7496117ca76.webp', true, '2026-05-20 14:54:05', '2026-05-20 16:36:26', -7.2554948, 112.7402360, NULL) ON CONFLICT (id) DO NOTHING;
