INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('de31d39e-d283-4d3b-8aa6-f484d2bfd02f', '91a1d379-c196-4e45-906b-1c57652e7e84', 'Puncak Saka Kulon Progo', 'Bukit tertinggi di Kulon Progo (ketinggian 986 mdpl) dengan pemandangan 360° — hamparan kebun teh, kota Wates, dan Samudra Hindia. Camping ground yang populer di kalangan anak muda Yogyakarta dengan sunrise yang memukau.', 'Nanggulan, Kulon Progo, DIY', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/de31d39e-d283-4d3b-8aa6-f484d2bfd02f.webp', true, '2026-05-20 14:55:39', '2026-05-20 16:40:50', -7.7968218, 110.1914612, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('77d55bb4-3139-404c-9b9f-10e09e35e142', '58ca1eda-c5a6-4894-aa52-fd0c18feb280', 'Mangga Probolinggo (Manalagi & Arumanis)', 'Probolinggo terkenal sebagai kota mangga dengan varietas Manalagi dan Arumanis yang memiliki cita rasa manis istimewa. Saat musim panen Oktober-Januari, ribuan pedagang mangga berjejer di sepanjang jalan kota menawarkan mangga segar dengan harga petani.', 'Pasar Baru Probolinggo, Jawa Timur', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/77d55bb4-3139-404c-9b9f-10e09e35e142.webp', true, '2026-05-20 14:56:10', '2026-05-20 16:41:05', -7.7547416, 113.2185938, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('051d5304-bbee-4a62-b580-70c046f6e233', '82bf2ebf-1804-43a5-afe9-e5f7877c01f1', 'Pasar Tagogapu', 'Pasar tradisional yang melayani warga Tagogapu dengan berbagai produk pertanian, ikan air tawar, dan kebutuhan sehari-hari.', 'Tagogapu, Bandung Barat', 'UMKM', 3.60, NULL, true, '2026-05-22 23:21:38', '2026-05-22 23:21:38', NULL, -6.8110000, 107.4649000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('af7ca0ab-9375-44b3-ba21-2869a7a5eec9', '892f354f-aced-412e-b429-c5f84ca0f410', 'Kupang Lamongan', 'Kuliner laut khas Lamongan berupa kerang kupang — kerang kecil berwarna putih — yang dimasak dengan bumbu petis dan jeruk nipis. Disajikan dengan lontong dan sate kerang, kupang menjadi kuliner unik yang hanya bisa dinikmati di pesisir Lamongan dan Sidoarjo.', 'Pasar Ikan Lamongan, Jl. Raya Babat, Lamongan', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/af7ca0ab-9375-44b3-ba21-2869a7a5eec9.webp', true, '2026-05-20 14:55:56', '2026-05-20 16:41:11', -7.1124365, 112.4202256, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('c91c1a98-a83e-43c4-8369-ebec05530047', '58ca1eda-c5a6-4894-aa52-fd0c18feb280', 'Gunung Bromo (via Probolinggo)', 'Gunung berapi aktif setinggi 2.329 mdpl yang terkenal dengan panorama sunrise spektakuler di atas lautan pasir (Sea of Sand). Stasiun Probolinggo adalah gerbang utama menuju Bromo — hanya 45 km dari stasiun menuju Cemoro Lawang.', 'TNBTS, Probolinggo, Jawa Timur', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/c91c1a98-a83e-43c4-8369-ebec05530047.webp', true, '2026-05-20 14:56:08', '2026-05-20 16:41:36', -7.7472000, 113.2194000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('30e99308-6ee4-420a-b37e-8b63e6a229cf', '892f354f-aced-412e-b429-c5f84ca0f410', 'Wisata Bahari Lamongan (WBL)', 'Taman wisata bahari terbesar di Jawa Timur yang terintegrasi dengan Goa Maharani (gua stalaktit indah). Berbagai wahana air, pertunjukan lumba-lumba, dan area bermain anak tersedia di komplek seluas 11 hektare di tepi laut Lamongan.', 'Paciran, Lamongan, Jawa Timur', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/30e99308-6ee4-420a-b37e-8b63e6a229cf.webp', true, '2026-05-20 14:55:54', '2026-05-20 16:41:38', -6.8703484, 112.3396790, NULL) ON CONFLICT (id) DO NOTHING;
