INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('bfb961b9-8037-4740-abe2-fe2cba10e8d0', '7b08d136-a028-40b2-b0dd-60706ee9b1da', 'Bukit Kapur Sekapuk Gresik', 'Bekas tambang kapur yang disulap menjadi destinasi wisata instagramable dengan tebing-tebing kapur putih yang megah. Spot foto dengan latar dinding kapur putih setinggi 30 meter dan cerukan-cerukan alami yang unik menjadi magnet wisatawan milenial.', 'Sekapuk, Ujungpangkah, Gresik', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/bfb961b9-8037-4740-abe2-fe2cba10e8d0.webp', true, '2026-05-20 14:55:43', '2026-05-20 16:40:20', -7.1547186, 112.5204282, NULL) ON CONFLICT (id) DO NOTHING;
