INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('4e3de4d0-dae3-4445-85a2-28406280f15b', 'f0d815f7-27f5-43a4-a4a1-504f11a5d11f', 'Tahu Ngawi', 'Tahu kuning khas Ngawi dengan tekstur padat, kenyal, dan rasa gurih yang khas. Berbeda dari tahu kota lain, tahu Ngawi menggunakan kedelai lokal pilihan dan proses pembuatan tradisional yang menghasilkan tahu berkualitas tinggi, populer sebagai oleh-oleh.', 'Sentra Tahu, Jl. Raya Ngawi', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/4e3de4d0-dae3-4445-85a2-28406280f15b.webp', true, '2026-05-20 14:56:02', '2026-05-20 16:41:01', -7.4422788, 111.3869462, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('392b0979-2366-4522-80d6-51e840e4ca07', 'd26192b6-d749-43e2-b251-3f4cc22ebd02', 'Gulai Kambing Bustaman Pak Sabar', 'Gulai kambing legendaris khas Semarang dengan kuah bening tanpa santan, dimasak dari serundeng halus dan rempah pilihan. Tekstur daging yang sangat empuk dan rasa yang gurih membuatnya jadi kuliner wajib di Kota Lama.', 'Gang Bustaman, Semarang Tengah', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/392b0979-2366-4522-80d6-51e840e4ca07.webp', true, '2026-05-20 14:52:23', '2026-05-20 16:41:55', -6.9636000, 110.4275000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('65b6b146-bfe2-46fd-ad3f-71f9b7d7e469', '35d18352-24e3-404a-8128-2e286537dd2f', 'Bandeng Asap Pasuruan', 'Ikan bandeng asap khas Pasuruan dengan proses pengasapan tradisional selama 4-6 jam menggunakan kayu pilihan. Aroma asap yang meresap sempurna menghasilkan rasa gurih-smoky yang unik. Menjadi oleh-oleh favorit dari kawasan pesisir Pasuruan.', 'Sentra Bandeng Asap, Bangil, Pasuruan', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/65b6b146-bfe2-46fd-ad3f-71f9b7d7e469.webp', true, '2026-05-20 14:56:07', '2026-05-20 16:42:05', -7.6377552, 112.9101355, NULL) ON CONFLICT (id) DO NOTHING;
