INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('8368a55d-68cf-461d-9bda-8fa8bb6d1523', '046f740f-0ecf-4960-8298-6eba206930c7', 'Malang Strudel', 'Oleh-oleh khas Malang yang hits — kue strudel dengan berbagai varian rasa: apel, coklat, keju, hingga pisang. Dikemas premium dan tahan lama untuk dibawa pulang. Jadi salah satu buah tangan paling dicari wisatawan yang berkunjung ke Malang.', 'Jl. Trunojoyo No.8, Klojen, Malang', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/8368a55d-68cf-461d-9bda-8fa8bb6d1523.webp', true, '2026-05-20 14:52:38', '2026-05-20 16:43:45', -7.9735129, 112.6235811, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('ebbd4655-b7ad-4e37-b0fe-355cfefc1add', 'cd888761-f3b5-4071-acd7-0484892c8c60', 'Lontong Balap Pak Gendut', 'Lontong balap khas Surabaya dengan perpaduan lontong, tauge, lentho goreng, dan kuah kaldu sapi bening. Dipadu sambal petis yang khas, menjadi sarapan favorit warga Surabaya.', 'Jl. Dharmahusada Indah No.2, Sukolilo, Surabaya', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/ebbd4655-b7ad-4e37-b0fe-355cfefc1add.webp', true, '2026-05-20 14:52:18', '2026-05-20 16:44:07', -7.2658000, 112.7522000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('db2b9849-c91c-42c4-961d-e437ca276f66', 'e88e39b5-2f31-43d8-9580-42bdc036cff9', 'Gudeg Lumintu Jember', 'Gudeg Jawa Timur khas Jember yang sudah ada sejak 1968. Berbeda dari gudeg Jogja yang manis, gudeg Lumintu lebih gurih dengan cita rasa khas Jawa Timur. Menu lain tersedia: soto, nasi campur, dan nasi pecel. Lokasi strategis dekat stasiun.', 'Jl. Kertanegara No.33, Kaliwates, Jember', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/db2b9849-c91c-42c4-961d-e437ca276f66.webp', true, '2026-05-20 14:53:18', '2026-05-20 16:44:24', -8.1793100, 113.6877397, NULL) ON CONFLICT (id) DO NOTHING;
