INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('a9372b31-e4a5-40d4-9e9e-75459bb1908a', '780daaaa-9f43-48c5-b7c9-b38c768ff4dd', 'Surabi Enhaii', 'Surabi khas Bandung dengan varian topping modern seperti coklat, keju, oncom, hingga pete. Dibuat dari tepung beras pilihan, menghasilkan tekstur lembut dengan pinggiran renyah.', 'Jl. Setiabudi No.186, Bandung', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/a9372b31-e4a5-40d4-9e9e-75459bb1908a.webp', true, '2026-05-20 14:52:03', '2026-05-20 16:29:16', -6.9121000, 107.6090000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('f4c0ad86-b4a3-462f-b0ab-590450caa3b1', '7c6aa826-60b4-41a3-ac80-cdcd85dce3f8', 'Batik Mirota Batik', 'Pusat belanja batik dan kerajinan Yogyakarta yang terlengkap. Menjual batik tulis, batik cap, wayang kulit, perak, dan berbagai souvenir khas Jogja dengan kualitas premium.', 'Jl. Ahmad Yani No.9, Ngupasan, Yogyakarta', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/f4c0ad86-b4a3-462f-b0ab-590450caa3b1.webp', true, '2026-05-20 14:52:10', '2026-05-20 16:29:24', -7.6762359, 110.4170680, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('2a5f6337-2e15-4dbd-bacf-715c22eb4843', '052c79a7-6c65-41c8-b3e1-c2dd03bb5bea', 'Nasi Kapau Uni Lis', 'Nasi Kapau Minang dengan lauk berupa gulai cubadak, rendang, ayam pop, dan berbagai sayur khas Sumatera Barat. Cita rasa autentik di tengah keramaian Pasar Senen.', 'Jl. Senen Raya, Pasar Senen, Jakarta Pusat', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/2a5f6337-2e15-4dbd-bacf-715c22eb4843.webp', true, '2026-05-20 14:51:59', '2026-05-20 16:29:26', -6.1728241, 106.8377011, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('77bf05a0-ece7-4537-ab71-c366fe7b0b06', '98d07c34-4170-4f9e-b097-5356b571ac7b', 'Kampung Adat Cikondang', 'Desa adat Sunda yang masih mempertahankan tradisi leluhur dengan rumah-rumah panggung tradisional. Pengunjung dapat menyaksikan ritual adat, kesenian lokal, dan belajar tentang kearifan lokal.', 'Desa Lamajang, Pangalengan, Bandung', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/77bf05a0-ece7-4537-ab71-c366fe7b0b06.webp', true, '2026-05-20 14:52:06', '2026-05-20 16:29:34', -6.9244000, 107.6438000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('9401dc72-e255-43b2-8b7a-0fa204c1fc73', 'bc07fd7f-2986-49c8-a534-c05d147a2cad', 'Batik Semar Jakarta', 'Toko batik premium yang menjual berbagai motif batik khas Indonesia. Didirikan sejak 1956, menawarkan batik tulis, batik cap, dan batik printing dengan kualitas terjamin.', 'Jl. Pintu Besar Selatan No.51, Jakarta Pusat', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/9401dc72-e255-43b2-8b7a-0fa204c1fc73.webp', true, '2026-05-20 14:51:56', '2026-05-20 16:29:43', -6.1754345, 106.8030020, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('77cf8968-2933-4126-b6de-f9e86b082c8c', '79993c21-20b5-4f61-af26-1a37dc95c7ec', 'Bakpia Pathok 25', 'Produsen bakpia legendaris Yogyakarta yang berdiri sejak 1955 di Pathok. Bakpia isi kacang hijau dengan kulit tipis renyah menjadi oleh-oleh wajib bagi wisatawan yang berkunjung ke Jogja.', 'Jl. AIP KKO Usman dan Harun No.25, Pathok, Yogyakarta', 'Kuliner', 4.75, NULL, true, '2026-05-20 14:52:12', '2026-05-21 11:41:31', -7.7968817, 110.3609549, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('530fedcb-a4f3-46a3-a3f2-ff6e0c4ec8d0', 'd475371a-cb92-4314-ba8b-83561f5e6f8a', 'Nasi Jamblang Ibu Nur', 'Nasi jamblang khas Cirebon yang disajikan dengan daun jati sebagai pembungkus. Tersedia puluhan pilihan lauk: sambal goreng kentang, tahu, tempe, perkedel, paru, dan berbagai masakan rumahan. Tempat makan rakyat paling autentik di Cirebon.', 'Jl. Cangkring 2 No.34, Cirebon', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/530fedcb-a4f3-46a3-a3f2-ff6e0c4ec8d0.webp', true, '2026-05-20 14:52:42', '2026-05-20 16:29:49', -6.7144395, 108.5549726, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('9f2cc03c-4ff9-4f9e-9fce-53e05133b574', '905b6cf3-b3ed-48ca-8ee0-11d68813279a', 'Pura Mangkunegaran', 'Istana kerajaan Kadipaten Mangkunegaran yang dibangun 1757. Pendopo agung seluas 3.400 m² menjadi salah satu yang terbesar di Jawa. Museum menyimpan koleksi perhiasan, senjata, wayang, dan artefak kerajaan bernilai tinggi.', 'Jl. Ronggowarsito, Keprabon, Banjarsari, Solo', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/9f2cc03c-4ff9-4f9e-9fce-53e05133b574.webp', true, '2026-05-20 14:52:33', '2026-05-20 16:32:00', -7.5661670, 110.8230626, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('e2efbec0-f1e0-4339-a9dc-ebbd0be72cc7', 'bc07fd7f-2986-49c8-a534-c05d147a2cad', 'Soto Betawi H. Ma''ruf', 'Soto Betawi otentik dengan kuah santan kental yang kaya rempah. Daging sapi empuk, kentang goreng, dan tomat segar membuat sajian ini menjadi favorit warga Jakarta sejak 1940-an.', 'Jl. Kramat Raya No.13, Jakarta Pusat', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/e2efbec0-f1e0-4339-a9dc-ebbd0be72cc7.webp', true, '2026-05-20 14:51:57', '2026-05-20 16:29:28', -6.1809884, 106.8427781, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('58233790-f143-4063-9b3c-adddef654e33', '79993c21-20b5-4f61-af26-1a37dc95c7ec', 'Sate Klathak Pak Pong', 'Sate klathak khas Bantul dengan daging kambing muda yang ditusuk jeruji besi bukan bambu. Metode pemanggangan unik ini menghasilkan pematangan merata, disajikan dengan kuah tongseng dan nasi.', 'Jl. Imogiri Timur KM 10, Jejeran, Bantul, Yogyakarta', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/58233790-f143-4063-9b3c-adddef654e33.webp', true, '2026-05-20 14:52:14', '2026-05-21 01:09:38', -7.8712496, 110.3872742, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('6669906f-3358-45b8-b376-46ef79b60f15', '5eb9eeb7-0b4b-4218-b0b6-64bee05a98e3', 'Sate Buntel Pak H. Kasdi', 'Legenda sate buntel Solo sejak puluhan tahun. Daging kambing cincang dibungkus lemak tipis lalu dibakar hingga harum, menghasilkan tekstur lembut dan bumbu meresap sempurna tanpa bau prengus. Berlokasi satu menit jalan kaki dari Stasiun Balapan.', 'Jl. Wolter Monginsidi No.93, Banjarsari, Solo', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/6669906f-3358-45b8-b376-46ef79b60f15.webp', true, '2026-05-20 14:52:28', '2026-05-20 16:30:42', -7.5575000, 110.8222000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('63cdf842-ad7d-458d-a458-bd63de5cd75e', 'cd888761-f3b5-4071-acd7-0484892c8c60', 'Rawon Setan Mbak Endang', 'Rawon hitam pekat khas Surabaya yang terkenal. Dinamakan "Setan" karena buka hanya tengah malam. Kuah kental dari kluwek dengan daging sapi yang empuk.', 'Jl. Embong Malang No.78, Surabaya', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/63cdf842-ad7d-458d-a458-bd63de5cd75e.webp', true, '2026-05-20 14:52:17', '2026-05-20 16:31:02', -7.2598186, 112.7362381, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('a66e1b21-d668-4638-9726-2c8836448c68', '046f740f-0ecf-4960-8298-6eba206930c7', 'Jalan Ijen Boulevard', 'Jalan hijau ikonik Malang bergaya Eropa dengan pohon palem berjajar rapi di median jalan. Setiap minggu pagi ditutup untuk Car Free Day dan dipenuhi pedagang, seniman jalanan, serta warga berolahraga. Spot foto favorit di Malang.', 'Jl. Ijen, Oro-oro Dowo, Klojen, Malang', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/a66e1b21-d668-4638-9726-2c8836448c68.webp', true, '2026-05-20 14:52:39', '2026-05-20 16:30:50', -7.9672061, 112.6241757, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('bd9d1897-b254-4700-b0de-4d76ec0cfb32', 'a8104542-ad6b-4e83-bd6f-857fa32194d0', 'Masjid Agung Jawa Tengah', 'Masjid megah bergaya arsitektur Jawa-Arab-Romawi yang mampu menampung 15.000 jamaah. Menara setinggi 99 meter dilengkapi teropong untuk melihat kota Semarang dari ketinggian. Wisata religi dan arsitektur sekaligus.', 'Jl. Gajah Raya, Sambirejo, Semarang Timur', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/bd9d1897-b254-4700-b0de-4d76ec0cfb32.webp', true, '2026-05-20 14:52:27', '2026-05-20 16:30:06', -6.9836458, 110.4455923, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('8e21c043-b2d2-4628-b382-f4fd0bab4e02', '962460e6-c222-4725-a275-1e7a8846019f', 'Getuk Goreng Sokaraja Haji Tohirin', 'Oleh-oleh khas Banyumas yang wajib dibawa pulang. Getuk goreng Sokaraja dibuat dari singkong pilihan dengan rasa manis gurih, digoreng renyah di luar namun lembut di dalam. Sudah ada sejak 1918 dan menjadi ikon kuliner Purwokerto.', 'Jl. Jend. Sudirman, Sokaraja, Banyumas', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/8e21c043-b2d2-4628-b382-f4fd0bab4e02.webp', true, '2026-05-20 14:52:47', '2026-05-20 16:31:38', -7.4378000, 109.2253000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('1cc4e403-cfe5-4670-920b-5a56553040a3', 'a8104542-ad6b-4e83-bd6f-857fa32194d0', 'Lumpia Gang Lombok', 'Lumpia Semarang paling legendaris sejak 1800-an, menggunakan resep asli perpaduan Tionghoa-Jawa. Isi rebung, telur, udang, dan ayam yang berlimpah dibungkus kulit tipis renyah — wajib bawa pulang sebagai oleh-oleh.', 'Gang Lombok No.11, Semarang Tengah', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/1cc4e403-cfe5-4670-920b-5a56553040a3.webp', true, '2026-05-20 14:52:26', '2026-05-20 16:31:32', -6.9737608, 110.4271197, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('6931e5d7-2267-40f2-a74b-92d0f0f54445', '529327b9-28f6-4700-866d-b8e7a3199c8e', 'Perkebunan Nanas Subang', 'Subang dikenal sebagai "Kota Nanas" dengan perkebunan nanas terluas di Jawa Barat. Pengunjung dapat memetik nanas langsung dari kebun, melihat proses pengolahan, dan membeli olahan nanas segar — selai, keripik, dodol nanas — langsung dari petani.', 'Jalancagak, Subang', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/6931e5d7-2267-40f2-a74b-92d0f0f54445.webp', true, '2026-05-20 14:56:18', '2026-05-20 16:29:45', -6.6772132, 107.6881135, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('bbad27a4-5128-431d-aeec-076464a7ed4e', '7a56e769-d853-4d95-b830-676ae09b1e77', 'Batik Pekalongan Pasar Setono Betek', 'Pusat grosir batik Pekalongan terbesar tempat para pedagang batik dari seluruh Indonesia berbelanja. Ribuan motif batik tersedia dengan harga sangat terjangkau. Pekalongan diakui UNESCO sebagai kota batik dunia.', 'Jl. Dr. Sutomo, Setono Betek, Pekalongan', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/bbad27a4-5128-431d-aeec-076464a7ed4e.webp', true, '2026-05-20 14:53:09', '2026-05-20 16:33:11', -6.8881000, 109.6731000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('83a5cdab-211e-4b7b-a11f-1c24ea3d6bb1', '1c3f1ee8-4438-4779-a487-ba8774e4ead8', 'Sate Maranggi Banjar', 'Sate maranggi khas Sunda dengan daging sapi/kambing yang dimarinasi bumbu rempah khas kemudian dibakar arang. Berbeda dari sate pada umumnya, sate maranggi disajikan tanpa bumbu kacang — cukup sambal oncom segar dan irisan tomat.', 'Jl. Sudirman No.28, Banjar', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/83a5cdab-211e-4b7b-a11f-1c24ea3d6bb1.webp', true, '2026-05-20 14:53:15', '2026-05-20 16:33:23', -7.3619000, 108.5394000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('166e560b-4fa1-4486-9b11-721c47695b51', 'd26192b6-d749-43e2-b251-3f4cc22ebd02', 'Kawasan Kota Lama Semarang', 'Kawasan heritage bersejarah seluas 31 hektare bergaya arsitektur Eropa abad ke-17 hingga ke-19. Dijuluki "Little Netherlands", dipenuhi gedung kolonial yang kini beralih fungsi menjadi kafe, galeri seni, dan ruang kreatif.', 'Jl. Letjen Suprapto, Semarang Utara', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/166e560b-4fa1-4486-9b11-721c47695b51.webp', true, '2026-05-20 14:52:20', '2026-05-20 16:30:49', -6.9636000, 110.4275000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('cbd3ca67-e216-4b72-9ff8-94b9aa7fc4fc', '25c4d072-5661-4cf6-9225-9d99660339f9', 'Goa Selomangleng', 'Goa bersejarah peninggalan Kerajaan Kediri abad ke-11 yang dipahat di batu andesit. Di dalamnya terdapat relief kisah Arjunawiwaha karya Mpu Kanwa. Terletak di lereng Gunung Klotok yang hijau dan segar.', 'Desa Pojok, Mojoroto, Kediri', 'Wisata', 4.33, NULL, true, '2026-05-20 14:52:56', '2026-05-20 16:33:17', -7.8081313, 111.9732714, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('419d1fba-8515-4b07-b0d3-ceb68f321b01', '93e682a5-bb4d-4ecb-b4bc-81449842407a', 'Kampung Adat Baduy', 'Komunitas adat Suku Baduy yang hidup sepenuhnya selaras alam tanpa teknologi modern. Wisatawan dapat mengunjungi Baduy Luar untuk berinteraksi langsung, trekking melalui hutan, dan menyaksikan kain tenun tradisional buatan tangan yang indah.', 'Kanekes, Leuwidamar, Lebak, Banten', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/419d1fba-8515-4b07-b0d3-ceb68f321b01.webp', true, '2026-05-20 14:54:58', '2026-05-20 16:38:21', -6.3553000, 106.2550000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('7bfe8a8a-169f-4065-a8fd-b66959b9db74', '82d1b189-c47b-4521-967b-de2b916acfd9', 'Pecel Madiun Bu Rukmini', 'Pecel Madiun yang sudah terkenal ke seluruh Indonesia — bumbu kacang halus dengan rasa gurih, manis, dan sedikit pedas disiram di atas aneka sayuran rebus segar. Sajian autentik khas Madiun yang wajib dicoba setiap wisatawan.', 'Jl. Kolonel Marhadi No.7, Madiun', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/7bfe8a8a-169f-4065-a8fd-b66959b9db74.webp', true, '2026-05-20 14:53:01', '2026-05-20 16:33:30', -7.6300000, 111.5292000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('1bc0f1a6-44cd-4cc4-b5b9-5f5340d24165', '101a2582-4e74-44d1-b572-059679af8755', 'Situ Gede Tasikmalaya', 'Danau alami di tengah kota Tasikmalaya yang dikelilingi pepohonan hijau dan dilengkapi pulau kecil di tengahnya. Pengunjung bisa menikmati perahu, memancing, atau sekadar bersantai menikmati suasana danau yang tenang dan asri.', 'Jl. Situ Gede, Mangkubumi, Tasikmalaya', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/1bc0f1a6-44cd-4cc4-b5b9-5f5340d24165.webp', true, '2026-05-20 14:53:13', '2026-05-20 16:32:43', -7.3357034, 108.2044511, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('7f3f0159-3a9c-46a1-94d6-0e66b7736c1c', '759ce88e-d229-471a-b8a0-2cf0e2ff69bf', 'Kupat Glabed Tegal', 'Kuliner khas Tegal yang wajib dicoba — ketupat disiram kuah kuning kental dari tepung beras berbumbu kunyit dan rempah, ditambah potongan tempe goreng dan mi. Rasanya gurih creamy khas, sangat berbeda dari makanan berkuah di daerah lain.', 'Jl. Werkudoro, Tegal Timur, Kota Tegal', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/7f3f0159-3a9c-46a1-94d6-0e66b7736c1c.webp', true, '2026-05-20 14:53:04', '2026-05-20 16:32:58', -6.8689000, 109.1333000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('71124540-b449-4fd5-b5c6-63f4489dcc4a', '23ffd64f-e657-432c-8073-09f7b2b618d7', 'Pusat Oleh-Oleh Khas Tangerang', 'Toko oleh-oleh terpercaya yang menjual berbagai produk khas Tangerang seperti dodol, kue gipang beras ketan, rengginang, dan berbagai camilan tradisional Betawi-Tionghoa yang dikemas modern sebagai buah tangan.', 'Jl. Daan Mogot No.77, Sukasari, Tangerang', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/71124540-b449-4fd5-b5c6-63f4489dcc4a.webp', true, '2026-05-20 14:53:54', '2026-05-20 16:34:26', -6.1769753, 106.6320106, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('04ae8c94-6ba2-44a6-8622-c945274b0afe', '0ba51731-c208-4cb5-9a15-0741341536c8', 'Sego Tempong Bu Sinar', 'Nasi tempong adalah kuliner khas Banyuwangi — nasi panas disajikan dengan lauk ikan/ayam goreng, tempe, tahu, dan sayuran rebus, disiram sambal tomat mentah yang sangat pedas. "Tempong" artinya tampar — menggambarkan pedasnya yang luar biasa.', 'Jl. Brawijaya No.55, Banyuwangi', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/04ae8c94-6ba2-44a6-8622-c945274b0afe.webp', true, '2026-05-20 14:53:22', '2026-05-20 16:34:39', -8.1175000, 114.3853000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('c6fb26f5-ae2d-49e8-bbd8-4ad62ea35ef1', '91a1d379-c196-4e45-906b-1c57652e7e84', 'Gebleg Kulon Progo', 'Makanan tradisional khas Kulon Progo berbahan tepung tapioka yang dikukus lalu digoreng. Tekstur kenyal dengan rasa gurih asin menjadi camilan unik yang hanya tersedia di Kulon Progo. Kini diolah menjadi berbagai produk modern seperti bakpia gebleg dan rengginang gebleg.', 'Pasar Wates, Kulon Progo, DIY', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/c6fb26f5-ae2d-49e8-bbd8-4ad62ea35ef1.webp', true, '2026-05-20 14:55:40', '2026-05-20 16:39:42', -7.8617604, 110.1582930, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('dea4187b-e526-4148-8954-985cbb726978', '101a2582-4e74-44d1-b572-059679af8755', 'Kupat Tahu Kabita', 'Kuliner legendaris Tasikmalaya sejak 1976. Kupat (ketupat) dan tahu dipadukan dengan bumbu kacang khas yang lebih encer dan segar dibanding bumbu gado-gado. Disajikan dengan mi kuning, tauge, dan kerupuk — sarapan wajib warga Tasik.', 'Jl. Otto Iskandar Dinata, Cihideung, Tasikmalaya', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/dea4187b-e526-4148-8954-985cbb726978.webp', true, '2026-05-20 14:53:11', '2026-05-20 16:33:48', -7.3306000, 108.2197000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('1129cf5e-d4e0-41e0-99a6-5fcf71a81101', '1c3f1ee8-4438-4779-a487-ba8774e4ead8', 'Taman Kota Langensari Banjar', 'Taman kota Banjar yang asri dan bersih dengan berbagai fasilitas rekreasi keluarga. Terdapat kolam bermain anak, jogging track, gazebo, dan area kuliner dengan berbagai jajanan khas Priangan Timur.', 'Jl. Kapten Jamhur, Langensari, Banjar', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/1129cf5e-d4e0-41e0-99a6-5fcf71a81101.webp', true, '2026-05-20 14:53:17', '2026-05-20 16:33:41', -7.3654691, 108.6116479, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('1b8ae521-36bc-447a-95cb-73432ae8fb59', 'da5a1a86-293c-48ae-ac9a-2d3665db70bb', 'Sentra Kuliner Jakarta Timur', 'Kawasan kuliner Jakarta Timur dengan warung dan restoran yang menyajikan masakan khas daerah. Harga terjangkau dengan cita rasa autentik.', 'Pusat Kota Jakarta Timur', 'Kuliner', 3.90, NULL, true, '2026-05-23 00:09:46', '2026-05-23 00:09:46', NULL, -6.2147000, 106.8702000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('32a50ae2-e4c8-4bb2-b600-0695374db341', '0ba51731-c208-4cb5-9a15-0741341536c8', 'Batik Gajah Oling Banyuwangi', 'Pusat batik khas Banyuwangi dengan motif gajah oling yang unik — motif sulur meliuk menyerupai belalai gajah yang menjadi ciri khas budaya Using Banyuwangi. Tersedia kain batik, pakaian jadi, dan souvenir yang tidak ditemukan di kota lain.', 'Jl. Brawijaya No.109, Banyuwangi', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/32a50ae2-e4c8-4bb2-b600-0695374db341.webp', true, '2026-05-20 14:53:24', '2026-05-20 16:35:13', -8.1175000, 114.3853000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('83f071da-1644-44b1-be55-dc3878ce1531', 'c0fada2e-9396-4db6-9c0c-3ccdb7eaa72f', 'Bakmi Gang Kelinci', 'Bakmi legendaris Jakarta yang sudah berdiri sejak 1957 di gang sempit kawasan Pecinan. Bakmi ayam dengan kuah kaldu bening dan pangsit goreng renyah menjadi sajian yang selalu dipadati pengunjung dari berbagai penjuru Jakarta.', 'Gang Kelinci No.1, Pasar Baru, Jakarta Pusat', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/83f071da-1644-44b1-be55-dc3878ce1531.webp', true, '2026-05-20 14:53:36', '2026-05-20 16:34:54', -6.1626704, 106.8337321, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('5fc009d2-3039-478a-a3a8-976a05b26425', '984da642-8a35-4c40-8638-38cf51e722b1', 'Gunung Bromo', 'Gunung berapi aktif yang paling terkenal di Indonesia dengan lautan pasir, kawah aktif, dan panorama matahari terbit yang memukau.', 'Probolinggo - Bromo Tengger Semeru', 'Wisata', 5.00, 'https://cdn.jejakjalur.project-n.site/destinasi/5fc009d2-3039-478a-a3a8-976a05b26425.webp', true, '2026-05-22 23:41:49', '2026-05-23 04:17:19', NULL, -7.9425000, 112.9530000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('6925fd8a-acd7-4f6f-b707-aaa9733f8856', '759ce88e-d229-471a-b8a0-2cf0e2ff69bf', 'Taman Pancasila Tegal', 'Taman kota yang sering menjadi pusat festival UMKM dan kuliner Tegal. Di sekitarnya berjajar pedagang es krim tempo dulu, martabak Tegal, wedang asle, dan jajanan khas yang sudah ada sejak generasi. Ramai terutama sore dan malam hari.', 'Jl. Ahmad Yani, Panggung, Tegal Timur', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/6925fd8a-acd7-4f6f-b707-aaa9733f8856.webp', true, '2026-05-20 14:53:05', '2026-05-20 16:31:55', -6.8689000, 109.1333000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('61b59d53-e2f5-4eeb-b745-b8a46fe68ef6', '90516e78-cfbe-44e1-9d05-a9ef254e899c', 'Sate Padang Ajo Ramon', 'Sate Padang autentik dengan kuah kari kuning kental yang kaya rempah. Sate daging sapi yang empuk dengan bumbu khas Minang yang pedas dan harum menjadikannya salah satu sate terenak di Jakarta Selatan.', 'Jl. Bukit Duri, Tebet, Jakarta Selatan', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/61b59d53-e2f5-4eeb-b745-b8a46fe68ef6.webp', true, '2026-05-20 14:53:40', '2026-05-20 16:35:22', -6.2210945, 106.8584257, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('d6d4dc86-8576-442e-b472-ce302470f084', '33168bd1-e746-4380-a5f4-cfd8eab7b42d', 'Warung Bu Kris', 'Warung makan legendaris Jawa Timur di Jakarta Selatan yang terkenal dengan ayam penyet dan sambal terasi ekstra pedasnya. Dikenal luas oleh pekerja kantoran dan mahasiswa dengan porsi besar dan cita rasa autentik.', 'Jl. Radio Dalam, Gandaria Utara, Kebayoran Baru, Jakarta Selatan', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/d6d4dc86-8576-442e-b472-ce302470f084.webp', true, '2026-05-20 14:53:44', '2026-05-20 16:35:24', -6.2499382, 106.7917687, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('901abe23-37cf-4097-9969-357bc301d551', '7ef3a874-41a3-433e-a497-6c7f302cc999', 'Soto Kuning Pak Yusuf Bogor', 'Soto kuning khas Bogor dengan kuah santan berwarna kuning cerah, kaya rempah jahe dan kunyit. Diisi dengan potongan daging sapi, jeroan, dan perkedel kentang. Sudah menjadi ikon kuliner Bogor yang dicari wisatawan sejak generasi ke generasi.', 'Jl. Suryakencana No.229, Bogor Tengah', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/901abe23-37cf-4097-9969-357bc301d551.webp', true, '2026-05-20 14:53:29', '2026-05-20 16:35:30', -6.5950000, 106.7903000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('d24b7aa7-6d76-438f-9bb6-a65780851461', 'd1757c19-58ea-444e-b405-fa99bc349a2c', 'Coban Sewu (Tumpak Sewu)', 'Air terjun paling dramatis di Indonesia yang jatuh dari ketinggian 120 meter dengan lebar hingga 120 meter seperti tirai raksasa. Pemandangan dari atas kawah terlihat seperti ribuan air terjun (sewu = seribu) yang mengalir bersamaan.', 'Pronojiwo, Lumajang, Jawa Timur', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/d24b7aa7-6d76-438f-9bb6-a65780851461.webp', true, '2026-05-20 14:56:11', '2026-05-20 16:42:07', -8.2116602, 112.9420495, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('6f145c62-cee8-47f3-bbd4-265dc35eb49e', 'e5f525d4-c74f-4464-80f4-956f77221f2a', 'Batik Bayat Klaten', 'Sentra batik tulis khas Klaten dari Desa Bayat yang sudah terkenal sejak ratusan tahun. Motif-motifnya merupakan perpaduan unik antara gaya Yogyakarta dan Solo dengan warna-warna alam yang khas, dijual langsung dari pengrajin lokal.', 'Desa Bayat, Bayat, Klaten, Jawa Tengah', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/6f145c62-cee8-47f3-bbd4-265dc35eb49e.webp', true, '2026-05-20 14:53:59', '2026-05-20 16:35:49', -7.7780738, 110.6250136, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('bef53221-a879-42fa-a057-0a1698e0351e', '30d391c5-5ab3-4d4c-a39c-505a7bb10129', 'Soto Betawi H. Hasan Bekasi', 'Soto Betawi legendaris Bekasi dengan kuah santan kental kecoklatan yang gurih dan kaya rempah. Daging sapi yang empuk, kentang goreng, dan emping membuat sajian ini selalu ramai antrian setiap hari.', 'Jl. Ir. H. Juanda No.5, Bekasi Timur, Kota Bekasi', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/bef53221-a879-42fa-a057-0a1698e0351e.webp', true, '2026-05-20 14:53:47', '2026-05-20 16:35:37', -6.2356000, 106.9947000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('63f474e9-c845-4dea-ad54-c39d81b70e9f', 'dad55e36-6867-42b4-921a-4307a38bbe2b', 'Restoran Bale Raos', 'Restoran eksklusif yang menyajikan masakan keraton Yogyakarta — menu autentik yang dulunya hanya tersaji di meja makan Sultan. Berlokasi di dalam komplek Keraton, menawarkan pengalaman makan dalam suasana budaya Jawa yang agung.', 'Jl. Magangan Kulon No.1, Keraton, Yogyakarta', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/63f474e9-c845-4dea-ad54-c39d81b70e9f.webp', true, '2026-05-20 14:54:00', '2026-05-20 16:36:20', -7.8084796, 110.3631118, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('5e8214e3-44d5-4e1a-93d7-521af663dc40', 'dc54c9b2-0f4b-493e-91e8-4fcdc5ca5f4f', 'Sate Kambing H. Abdullah Sudirman', 'Warung sate kambing legendaris di kawasan Sudirman yang sudah beroperasi sejak 1978. Sate kambing empuk dengan bumbu kecap manis khas Jakarta, disajikan dengan lontong dan kuah soto kambing gurih.', 'Jl. Kebon Sirih, Menteng, Jakarta Pusat', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/5e8214e3-44d5-4e1a-93d7-521af663dc40.webp', true, '2026-05-20 14:54:11', '2026-05-20 16:36:38', -6.1934800, 106.8288336, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('82f31135-8279-43b8-817c-c54c9b5a0846', 'ddcf510a-05e5-4f37-b7ad-702b116fcdb2', 'Keramik Plered Bandung Barat', 'Sentra keramik tradisional Plered yang sudah terkenal sejak abad ke-18. Pengunjung bisa melihat langsung proses pembuatan keramik dan gerabah khas Plered, serta membeli berbagai produk gerabah seni dengan harga langsung dari pengrajin.', 'Plered, Purwakarta — dapat diakses dari Stasiun Padalarang', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/82f31135-8279-43b8-817c-c54c9b5a0846.webp', true, '2026-05-20 14:54:32', '2026-05-20 16:36:52', -6.8425000, 107.4844000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('8eb8d4e7-32d4-44c3-b2cd-a9bba8b6e806', 'cd7cf2d0-2237-4770-93e2-a9e23524c8fd', 'Bakpia Pathok 25 Bantul', 'Produsen bakpia legendaris yang sudah ada sejak 1948. Bakpia dengan isian kacang hijau, coklat, dan keju dengan kulit tipis renyah menjadi oleh-oleh wajib Yogyakarta yang paling dicari wisatawan.', 'Jl. AIP II KS Tubun, Bantul, DIY', 'UMKM', 4.33, NULL, true, '2026-05-20 14:54:04', '2026-05-20 16:37:14', -7.7961358, 110.2842707, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('59a7744d-d727-4f26-a148-c90a9f85dde8', '8557d3ac-0ab0-4a5f-a078-00a9b289b9f1', 'Pasar Cibinong', 'Pasar tradisional ramai yang menjadi pusat perdagangan sayur, buah, dan kebutuhan pokok masyarakat Cibinong.', 'Jl. Mayor Oking, Cibinong, Bogor', 'UMKM', 3.80, NULL, true, '2026-05-22 23:11:14', '2026-05-22 23:11:14', NULL, -6.4728000, 106.8508000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('8077dc82-00d8-4039-b405-f0fb3c675007', '4b72caad-8fc6-4278-979d-053bfc5b8bf3', 'BSD City & AEON Mall', 'Kota mandiri modern terbesar di Tangerang Selatan dengan AEON Mall sebagai pusat perbelanjaan kelas dunia. Konsep mixed-use development dengan hunian, perkantoran, dan fasilitas hiburan terlengkap di kawasan BSD.', 'BSD City, Serpong, Tangerang Selatan', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/8077dc82-00d8-4039-b405-f0fb3c675007.webp', true, '2026-05-20 14:54:25', '2026-05-20 16:36:43', -6.2958322, 106.6655413, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('b6eb6b70-2aa5-488c-9d41-9150770c4f9b', '2e5802ae-3b90-4468-86fc-a75ea957d26a', 'Sate Maranggi Cibungur', 'Sate daging sapi atau kambing khas Cianjur-Purwakarta dengan bumbu rempah manis-gurih yang dibakar di atas arang. Berbeda dari sate Madura, Sate Maranggi menggunakan potongan daging yang lebih besar dengan bumbu meresap sempurna.', 'Jl. Raya Cibungur, Cianjur', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/b6eb6b70-2aa5-488c-9d41-9150770c4f9b.webp', true, '2026-05-20 14:54:37', '2026-05-20 16:37:19', -6.4717694, 107.4804409, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('95ee8eb7-cd5b-43b5-a259-b3eb92e460a3', '9e750b4a-1089-441f-a9ec-864bb2ce9b63', 'Mangga Gedong Gincu Indramayu', 'Sentra mangga Gedong Gincu dan Cengkir khas Indramayu — mangga premium yang hanya tumbuh di wilayah tertentu di Indramayu. Tersedia langsung dari kebun petani dengan rasa manis-segar yang tiada duanya, terutama di musim panen Mei-Agustus.', 'Sentra Mangga Indramayu, Jl. Raya Indramayu', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/95ee8eb7-cd5b-43b5-a259-b3eb92e460a3.webp', true, '2026-05-20 14:54:49', '2026-05-20 16:37:25', -6.4750000, 108.3019000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('eae445f0-bebb-4103-b272-0728e7eca654', 'c5f53337-a27b-4682-ae48-a5fbd7bf7ee0', 'Rabeg Khas Banten', 'Masakan khas Banten berupa gulai kambing berbumbu hitam legam dengan rempah ketumbar, merica, jahe, dan bawang yang kuat. Hidangan bersejarah yang konon sudah ada sejak zaman Kesultanan Banten dan kini menjadi kuliner ikonik Serang.', 'Jl. Raya Serang, Banten', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/eae445f0-bebb-4103-b272-0728e7eca654.webp', true, '2026-05-20 14:54:55', '2026-05-20 16:37:35', -6.2201711, 106.5624683, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('1133cf06-ea4c-4f57-89ae-2954469c2ff9', '9d5cac13-e6e8-4f9d-b710-d294b1d416a9', 'Kawah Ijen', 'Gunung berapi dengan kawah biru elektrik paling terkenal di dunia. Api biru yang menyala di malam hari menciptakan pemandangan yang luar biasa.', 'Licin, Banyuwangi', 'Wisata', 4.80, 'https://cdn.jejakjalur.project-n.site/destinasi/1133cf06-ea4c-4f57-89ae-2954469c2ff9.webp', true, '2026-05-23 00:09:46', '2026-05-23 00:09:46', NULL, -8.0583000, 114.2422000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('2cc63dce-5adb-4a4f-b3ce-daf3722c4e61', '2e5802ae-3b90-4468-86fc-a75ea957d26a', 'Taman Bunga Nusantara', 'Taman bunga tematik seluas 35 hektare dengan koleksi lebih dari 20.000 tanaman bunga dari berbagai penjuru dunia. Taman bergaya Eropa, Jepang, dan tropis menjadikan tempat ini sebagai destinasi wisata keluarga terpopuler di Cianjur.', 'Jl. Mariwati KM 7, Sukaresmi, Cianjur', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/2cc63dce-5adb-4a4f-b3ce-daf3722c4e61.webp', true, '2026-05-20 14:54:35', '2026-05-20 16:38:16', -6.7277478, 107.0794088, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('1be56cd3-6187-4f82-9c10-0abae9522a67', '84afab3e-d235-49b9-80c4-236d19bc62f7', 'Pantai Sigandu Batang', 'Pantai wisata unggulan Batang dengan pasir putih kecoklatan, ombak tenang, dan pohon cemara berjejer indah. Dilengkapi area camping, wahana banana boat, dan kuliner seafood segar langsung dari nelayan setempat.', 'Jl. Pantai Sigandu, Batang, Jawa Tengah', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/1be56cd3-6187-4f82-9c10-0abae9522a67.webp', true, '2026-05-20 14:55:00', '2026-05-20 16:38:51', -6.8821569, 109.7562417, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('188d0fe3-eef3-490c-ade3-26502c0f51ff', 'ccbecb7e-5937-48a5-97b5-43c01c50ce47', 'Air Terjun Grojogan Sewu', 'Air terjun setinggi 81 meter yang megah di kawasan Tawangmangu. Dikelilingi hutan tropis dan menjadi wisata alam paling populer di lereng Gunung Lawu.', 'Tawangmangu, Karanganyar', 'Wisata', 4.50, 'https://cdn.jejakjalur.project-n.site/destinasi/188d0fe3-eef3-490c-ade3-26502c0f51ff.webp', true, '2026-05-23 00:09:46', '2026-05-23 00:09:46', NULL, -7.6651000, 111.1468000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('9017bc4e-b803-40ad-b622-d005629f031a', 'e5f525d4-c74f-4464-80f4-956f77221f2a', 'Candi Plaosan', 'Kompleks candi Buddha abad ke-9 yang dibangun oleh Rakai Pikatan sebagai hadiah untuk permaisuri Pramodhawardhani. Terdiri dari dua candi utama dengan relief Buddha yang indah di antara lanskap sawah hijau khas Jawa Tengah.', 'Bugisan, Prambanan, Klaten, Jawa Tengah', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/9017bc4e-b803-40ad-b622-d005629f031a.webp', true, '2026-05-20 14:53:55', '2026-05-20 16:35:40', -7.7405600, 110.5045511, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('dc3b9784-9979-44ea-9b33-d92058141096', '6dc07362-57d4-452c-a6bf-d34bbeed0a99', 'Pantai Ngebum Kendal', 'Pantai pasir putih yang bersih dan relatif sepi di pesisir Kendal dengan pohon kelapa dan bakau yang menjaga ekosistem. Spot favorit untuk menikmati sunrise, bersepeda santai, dan menikmati ikan bakar segar dari nelayan lokal.', 'Ngebum, Kaliwungu Selatan, Kendal', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/dc3b9784-9979-44ea-9b33-d92058141096.webp', true, '2026-05-20 14:55:06', '2026-05-20 16:38:26', -6.9278946, 110.3013472, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('815bd391-2de2-4980-a672-17a1acf695fb', '2a91ea0c-96d1-4dc5-bdba-b9b98f83f5a1', 'Situs Galuh Purba Ciamis', 'Kawasan heritage Kerajaan Galuh — salah satu kerajaan Hindu tertua di Jawa Barat. Berbagai situs megalitik, makam raja-raja Galuh, dan peninggalan budaya Sunda kuno tersebar di sekitar Ciamis yang bisa dijelajahi sebagai wisata sejarah.', 'Kawasan Cagar Budaya Galuh, Ciamis, Jawa Barat', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/815bd391-2de2-4980-a672-17a1acf695fb.webp', true, '2026-05-20 14:54:50', '2026-05-20 16:37:31', -7.3293002, 108.3561326, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('f0ee901a-25fd-4625-ac3c-a16990dcf0ed', '3b578686-a040-4210-8a0f-a78a43192713', 'Opak Ketan Karawang', 'Keripik opak berbahan ketan khas Karawang dengan cita rasa gurih dan renyah. Dibuat secara tradisional oleh UMKM lokal dengan berbagai varian rasa — original, bawang, dan pedas — yang menjadi oleh-oleh khas Karawang.', 'Sentra Opak Ketan, Telukjambe, Karawang', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/f0ee901a-25fd-4625-ac3c-a16990dcf0ed.webp', true, '2026-05-20 14:54:45', '2026-05-20 16:37:52', -6.3050826, 107.3002592, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('f13ab23a-3a2f-4634-b19c-3eaa51552e44', 'de589096-0817-4341-82fd-dfa659a2e9e1', 'Telur Asin Brebes', 'Brebes adalah ibu kota telur asin Indonesia — lebih dari 100 produsen telur asin tersebar di sini. Telur bebek yang diasinkan dengan campuran abu gosok dan garam selama 7-14 hari menghasilkan cita rasa gurih-asin yang khas dan tidak tertandingi.', 'Sentra Telur Asin, Jl. Jend. Sudirman, Brebes', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/f13ab23a-3a2f-4634-b19c-3eaa51552e44.webp', true, '2026-05-20 14:55:02', '2026-05-20 16:39:10', -6.8689493, 109.0313536, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('c53782d0-3635-48c8-bf68-4f371db68f86', 'ec72e8d2-69be-4346-ba36-d870d1fe8ae5', 'Onde-Onde Mojokerto', 'Onde-onde khas Mojokerto berukuran jumbo dengan isian kacang hijau yang berlimpah dan kulit wijen tebal. Berbeda dari onde-onde biasa, onde-onde Mojokerto menggunakan campuran tepung terigu dan tapioka yang menghasilkan tekstur lebih renyah di luar dan lembut di dalam.', 'Sentra Onde-onde, Jl. Mojopahit, Mojokerto', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/c53782d0-3635-48c8-bf68-4f371db68f86.webp', true, '2026-05-20 14:55:49', '2026-05-20 16:40:26', -7.4725876, 112.4340515, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('2f34be4b-0175-4d27-9e6b-82531034d1f0', 'f9d81219-a015-4615-b82f-fd5e566a352a', 'Kerajinan Kayu Jati Bojonegoro', 'Sentra kerajinan kayu jati terbesar di Jawa Timur dengan ratusan pengrajin menghasilkan furnitur, ukiran, dan aksesori rumah berkualitas premium. Kayu jati Bojonegoro dikenal sebagai yang terbaik di Indonesia karena serat kayu yang padat dan tahan lama.', 'Jl. Veteran, Bojonegoro, Jawa Timur', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/2f34be4b-0175-4d27-9e6b-82531034d1f0.webp', true, '2026-05-20 14:55:53', '2026-05-20 16:40:30', -7.1689923, 111.8952963, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('a09aa49d-1487-40bb-a07e-2cb32f441d2a', '1e53b655-0ef3-4d70-8af0-2a8551361f74', 'Timlo Solo Sastro', 'Sup khas Solo-Sukoharjo dengan isian sosis Solo, hati ayam, telur pindang, dan tahu dalam kuah kaldu bening yang segar. Berbeda dari soto, Timlo memiliki kuah yang lebih ringan dan segar, menjadikannya pilihan sarapan favorit warga Solo Raya.', 'Jl. Gatot Subroto, Sukoharjo', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/a09aa49d-1487-40bb-a07e-2cb32f441d2a.webp', true, '2026-05-20 14:55:23', '2026-05-20 16:40:43', -7.6063369, 110.8146338, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('53f99efe-fd79-4a8b-935e-e1f9fde38f3c', '8066faac-2a11-432b-b3ed-9f57d0338dc4', 'Agrowisata Wonosalam Jombang', 'Kawasan wisata agro di ketinggian 500-1.000 mdpl yang terkenal sebagai sentra durian montong dan alpukat terbaik di Jawa Timur. Tersedia kebun petik durian, villa alam, air terjun, dan festival durian tahunan yang meriah setiap Februari.', 'Wonosalam, Jombang, Jawa Timur', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/53f99efe-fd79-4a8b-935e-e1f9fde38f3c.webp', true, '2026-05-20 14:55:51', '2026-05-20 16:40:28', -7.7089248, 112.3708668, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('cb31fa5f-612f-4b34-9bc9-2042a0a25df3', 'c7d65290-a322-4ded-8222-f2faf11f7401', 'Kue Clorot Purworejo', 'Kue tradisional khas Purworejo berbahan tepung beras dan gula aren yang dibungkus daun kelapa muda berbentuk kerucut. Cita rasa manis dan gurih khas kue basah Jawa yang semakin langka, hanya bisa ditemukan di Purworejo dan sekitarnya.', 'Pasar Kutoarjo, Purworejo, Jawa Tengah', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/cb31fa5f-612f-4b34-9bc9-2042a0a25df3.webp', true, '2026-05-20 14:55:31', '2026-05-20 16:40:07', -7.7187621, 109.9100667, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('0ac7f5c6-5df5-4b25-8ce4-819dbef6a546', 'f75823be-9f39-4b0b-a0fb-10912b313a3e', 'Petis Udang Sidoarjo', 'Petis udang khas Sidoarjo — saus kental hitam berbahan dasar rebusan udang yang dipadatkan — menjadi bumbu wajib berbagai masakan Jawa Timur. Diproduksi oleh ratusan UMKM di Sidoarjo dengan kualitas terbaik untuk rujak, lontong balap, dan tahu campur.', 'Sentra Petis, Jl. Raya Porong, Sidoarjo', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/0ac7f5c6-5df5-4b25-8ce4-819dbef6a546.webp', true, '2026-05-20 14:55:46', '2026-05-20 16:40:05', -7.4475000, 112.7186000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('81c07b3f-cd39-43b1-b543-b351a9bbad90', 'c28816de-51ce-40b1-90c2-76e4fa290a67', 'Kerajinan Kulit Magetan', 'Sentra industri kerajinan kulit terbesar di Jawa Timur dengan ratusan toko dan pengrajin sepatu, sandal, tas, dan aksesori kulit. Kulit sapi dan kambing berkualitas diolah menjadi produk fashion premium dengan harga grosir langsung dari pengrajin.', 'Jl. Sawo, Selosari, Magetan', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/81c07b3f-cd39-43b1-b543-b351a9bbad90.webp', true, '2026-05-20 14:56:04', '2026-05-20 16:41:24', -7.5627203, 111.4515125, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('18ecaf72-d3c6-4bbd-9097-806d0ab6118b', '35d18352-24e3-404a-8128-2e286537dd2f', 'Air Terjun Kakek Bodo', 'Air terjun bertingkat di kawasan Prigen yang dikelilingi hutan tropis lebat dengan suasana segar dan sejuk. Trekking melewati hutan pinus menuju air terjun setinggi 40 meter ini menjadi aktivitas favorit wisatawan yang mengunjungi kawasan Tretes-Prigen.', 'Prigen, Pasuruan, Jawa Timur', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/18ecaf72-d3c6-4bbd-9097-806d0ab6118b.webp', true, '2026-05-20 14:56:06', '2026-05-20 16:41:03', -7.6805545, 112.6406232, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('2972ee06-4bb8-45df-acdd-13f9df8c0b0e', '76e8b12d-1e80-4fbb-9fe7-c0063088f572', 'Candi Sukuh', 'Candi Hindu abad ke-15 berdesain unik berbentuk piramida trapesium yang berbeda dari candi Jawa pada umumnya. Terletak di ketinggian 910 mdpl dengan latar belakang hutan lebat dan pemandangan kota Karanganyar yang indah dari atas.', 'Desa Berjo, Ngargoyoso, Karanganyar', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/2972ee06-4bb8-45df-acdd-13f9df8c0b0e.webp', true, '2026-05-20 14:55:19', '2026-05-20 16:40:55', -7.6273152, 111.1315373, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('133e3207-29e2-48cc-a8bd-d53c6d2dda3d', 'd1757c19-58ea-444e-b405-fa99bc349a2c', 'Pisang Agung Lumajang', 'Pisang Agung — varietas pisang terbesar di Indonesia yang beratnya bisa mencapai 1 kg per sisir. Hanya tumbuh di Lumajang dengan tekstur lembut dan manis alami. Tersedia dalam berbagai olahan: sale pisang, keripik pisang, dan selai pisang di sentra UMKM lokal.', 'Jl. A. Yani, Lumajang, Jawa Timur', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/133e3207-29e2-48cc-a8bd-d53c6d2dda3d.webp', true, '2026-05-20 14:56:12', '2026-05-20 16:41:17', -8.1232548, 113.3641550, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('4c2e4746-777f-47fe-9174-c183a34c7d12', '98d07c34-4170-4f9e-b097-5356b571ac7b', 'Taman Tegalega', 'Taman kota bersejarah seluas 16 hektare yang menjadi ruang hijau utama warga Bandung selatan. Terdapat patung Pangeran Diponegoro, area olahraga, dan amphiteater terbuka.', 'Jl. Otto Iskandar Dinata, Kiaracondong, Bandung', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/4c2e4746-777f-47fe-9174-c183a34c7d12.webp', true, '2026-05-20 14:52:04', '2026-05-20 16:44:11', -6.9348341, 107.6048337, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('e243837d-6779-4270-becc-45bf7c622575', 'b9b7ad71-291f-492e-8c85-c6ceaa436bde', 'Bawang Merah Nganjuk', 'Nganjuk adalah lumbung bawang merah terbesar di Jawa Timur. Pasar bawang merah terbesar di Jawa ada di sini, dengan aktivitas jual-beli yang ramai sejak subuh. Wisatawan dapat mengunjungi kebun bawang dan membeli langsung dari petani.', 'Pasar Kertosono, Nganjuk, Jawa Timur', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/e243837d-6779-4270-becc-45bf7c622575.webp', true, '2026-05-20 14:55:59', '2026-05-20 16:42:29', -7.5909287, 112.1052488, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('86a9741d-5a61-4e78-be8a-431733a34aaf', '2cdfd1f7-ea94-4248-8f39-24478e961033', 'Agrowisata Belimbing Karangsari', 'Desa wisata agro yang terkenal dengan belimbing jumbo khas Blitar. Pengunjung bisa memetik buah langsung dari pohon, mencicipi berbagai olahan belimbing, dan membeli produk UMKM pengolahan belimbing seperti sirup, keripik, dan selai.', 'Desa Karangsari, Sukorejo, Blitar', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/86a9741d-5a61-4e78-be8a-431733a34aaf.webp', true, '2026-05-20 14:52:54', '2026-05-20 16:43:34', -8.0950000, 112.1614000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('82cd6dfd-fe77-47ae-8a70-feb1ceec35ea', '905b6cf3-b3ed-48ca-8ee0-11d68813279a', 'Pasar Gede Hardjonagoro', 'Pasar tradisional ikonik Solo yang dibangun 1930 bergaya arsitektur kolonial. Surga kuliner pagi hari dengan aneka jajanan khas Solo: bubur gudeg, timlo, dawet telasih, intip goreng, dan berbagai camilan tradisional Jawa.', 'Jl. Jend. Urip Sumoharjo, Sudiroprajan, Solo', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/82cd6dfd-fe77-47ae-8a70-feb1ceec35ea.webp', true, '2026-05-20 14:52:32', '2026-05-22 14:51:01', -6.8135902, 107.2226794, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('653ae45b-77fc-4a71-a524-79e85f04cb73', '8066faac-2a11-432b-b3ed-9f57d0338dc4', 'Pesantren Tebuireng & Makam Gus Dur', 'Pondok pesantren bersejarah yang didirikan KH. Hasyim Asy''ari pada 1899 — kakek Presiden RI ke-4 Gus Dur. Makam Gus Dur (KH. Abdurrahman Wahid) menjadi tempat ziarah ratusan ribu pengunjung per tahun, dikelilingi suasana pesantren yang kental.', 'Tebuireng, Diwek, Jombang, Jawa Timur', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/653ae45b-77fc-4a71-a524-79e85f04cb73.webp', true, '2026-05-20 14:55:50', '2026-05-20 16:41:40', -7.6080571, 112.2363791, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('48f09445-9877-4664-9898-c500745e66c2', '892f354f-aced-412e-b429-c5f84ca0f410', 'Soto Lamongan Cak Mun', 'Soto ayam Lamongan autentik dengan kuah kuning bening yang kaya rempah. Berbeda dari soto lainnya, soto Lamongan menggunakan koya — bubuk kerupuk udang — yang ditaburkan di atas soto sehingga menghasilkan tekstur dan rasa yang sangat khas.', 'Jl. Veteran, Lamongan, Jawa Timur', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/48f09445-9877-4664-9898-c500745e66c2.webp', true, '2026-05-20 14:55:56', '2026-05-20 16:41:44', -7.1221532, 112.4220817, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('6619546f-d25c-4f75-b3c0-54af4bba8d9c', '9b9b5c27-b14c-4d1d-a647-faaccd6a76ed', 'Curug Cimahi (Curug Pelangi)', 'Air terjun setinggi 87 meter yang paling terkenal di Cimahi dengan nuansa mistis dan pemandangan luar biasa. Dijuluki Curug Pelangi karena efek cahaya yang menciptakan pelangi alami saat pagi hari. Akses hiking sekitar 30 menit dari parkiran.', 'Jl. Kolonel Masturi, Cisarua, Cimahi Utara', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/6619546f-d25c-4f75-b3c0-54af4bba8d9c.webp', true, '2026-05-20 14:54:33', '2026-05-20 16:44:54', -6.8736000, 107.5419000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('205054dc-ab1c-4589-9b5b-0cd9f52a74fe', '98d07c34-4170-4f9e-b097-5356b571ac7b', 'Sate Kambing Pak H. Yusuf', 'Sate kambing pilihan yang terkenal empuk dan tidak berbau prengus. Bumbu kecap spesial dengan irisan tomat dan bawang merah segar menjadi keunggulan warung sate ini sejak 1988.', 'Jl. Ibrahim Adjie No.5, Kiaracondong, Bandung', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/205054dc-ab1c-4589-9b5b-0cd9f52a74fe.webp', true, '2026-05-20 14:52:05', '2026-05-20 16:45:06', -6.9244000, 107.6438000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('c3c6af38-7fdc-4d98-8176-98b0011c26aa', '5eb9eeb7-0b4b-4218-b0b6-64bee05a98e3', 'Keraton Kasunanan Surakarta', 'Pusat kebudayaan Jawa yang megah di jantung kota Solo. Dibangun pada abad ke-18, keraton ini menyimpan koleksi artefak bersejarah dan budaya Jawa yang tak ternilai. Pengunjung dapat menyaksikan pertunjukan seni tradisional.', 'Jl. Sidikoro, Baluwarti, Solo', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/c3c6af38-7fdc-4d98-8176-98b0011c26aa.webp', true, '2026-05-20 14:52:28', '2026-05-20 16:45:16', -7.5789498, 110.8287042, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('ffadd78c-b361-4d07-a004-b293f8e705f7', '2e5802ae-3b90-4468-86fc-a75ea957d26a', 'Beras Pandanwangi Cianjur', 'Pusat penjualan beras Pandanwangi — varietas beras premium khas Cianjur dengan aroma pandan alami yang harum dan rasa pulen istimewa. Ditetapkan sebagai Indikasi Geografis oleh pemerintah, beras ini hanya tumbuh di dataran tinggi Cianjur.', 'Pasar Cianjur, Jl. Siti Jenab, Cianjur', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/ffadd78c-b361-4d07-a004-b293f8e705f7.webp', true, '2026-05-20 14:54:37', '2026-05-20 16:45:00', -6.8245938, 107.1426417, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('62a9f812-9403-4941-b937-5fdc44b65d15', 'c5f53337-a27b-4682-ae48-a5fbd7bf7ee0', 'Situs Banten Lama', 'Kawasan warisan budaya Kesultanan Banten (abad ke-16-19) yang mencakup Masjid Agung Banten, Keraton Surosowan, Keraton Kaibon, Benteng Speelwijk, dan Vihara Avalokitesvara. Saksi sejarah kejayaan perdagangan rempah Nusantara.', 'Banten, Kasemen, Serang, Banten', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/62a9f812-9403-4941-b937-5fdc44b65d15.webp', true, '2026-05-20 14:54:53', '2026-05-20 16:45:21', -6.0408270, 106.1599611, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('8d99107d-39b0-453e-b380-11f77bbe4577', '6dc07362-57d4-452c-a6bf-d34bbeed0a99', 'Klengkeng Kopyor Kendal', 'Kendal terkenal sebagai penghasil kelengkeng terbaik di Jawa Tengah, terutama varietas kopyor yang langka. Kebun-kebun kelengkeng di Kendal membuka wisata petik buah langsung dari pohon terutama saat musim panen Juli-Agustus.', 'Sentra Kelengkeng, Kaliwungu, Kendal', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/8d99107d-39b0-453e-b380-11f77bbe4577.webp', true, '2026-05-20 14:55:07', '2026-05-20 16:45:27', -6.9596163, 110.2549063, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('28d6f63c-795f-46b4-bf33-9cf85c79af71', 'bd240e45-e6e3-4289-8785-403904f05428', 'Pantai Anyer', 'Pantai paling populer di Banten yang terkenal dengan pasir putihnya dan pemandangan Gunung Krakatau di kejauhan. Berbagai resort, villa, dan restoran seafood berjejer di sepanjang pantai. Wisata snorkeling dan diving juga tersedia di perairan Anyer.', 'Anyer, Serang, Banten (40 km dari Stasiun Cilegon)', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/28d6f63c-795f-46b4-bf33-9cf85c79af71.webp', true, '2026-05-20 14:54:56', '2026-05-20 16:45:40', -6.0531453, 105.9147263, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('9c1df38b-2421-4e08-877b-7c2ec2f7d558', 'f1fd7844-7757-4d23-ad58-74ad9623b345', 'Bandeng Presto Demak', 'Ikan bandeng presto khas Demak yang dimasak dengan tekanan tinggi hingga seluruh tulang menjadi lunak dan bisa dimakan. Berbeda dari bandeng biasa, bandeng presto Demak menggunakan ikan bandeng segar dari tambak lokal dengan bumbu rempah yang meresap sempurna.', 'Pasar Demak, Jl. Sultan Patah, Demak', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/9c1df38b-2421-4e08-877b-7c2ec2f7d558.webp', true, '2026-05-20 14:55:11', '2026-05-20 16:45:52', -7.0254774, 110.5219125, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('298b97a3-f4a8-4b74-9c41-1d88f9efd269', 'd2b40f03-8023-46dc-b687-35906c36a5aa', 'Hutan Jati Blora', 'Kawasan hutan jati terluas di Pulau Jawa yang dikelola Perhutani dengan pohon jati berumur ratusan tahun yang megah.', 'Randublatung, Blora', 'Wisata', 4.10, NULL, true, '2026-05-22 23:41:49', '2026-05-22 23:41:49', NULL, -7.1921000, 111.3980000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('1d60cb71-3bf6-4d4d-944a-06e48966971c', '8f4b9442-1a09-4e5f-8a91-146d747fd7f1', 'Kota Kasablanka', 'Pusat perbelanjaan modern yang menggabungkan retail, restoran, dan berbagai hiburan dalam satu kompleks terpadu yang lengkap.', 'Jl. Casablanca Raya Kav.88, Jakarta Selatan', 'UMKM', 4.20, 'https://cdn.jejakjalur.project-n.site/destinasi/1d60cb71-3bf6-4d4d-944a-06e48966971c.webp', true, '2026-05-22 23:11:14', '2026-05-22 23:11:14', NULL, -6.2257000, 106.8417000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('0671b2cb-ae3d-477b-99b1-9f6184bb4d22', '7c6aa826-60b4-41a3-ac80-cdcd85dce3f8', 'Angkringan Lik Man', 'Angkringan legendaris Yogyakarta yang telah ada sejak 1950-an. Nasi kucing dengan lauk sederhana ditemani kopi joss — kopi hitam panas dengan arang membara — menjadi pengalaman kuliner autentik Jogja.', 'Jl. Wongsodirjan, dekat Stasiun Tugu, Yogyakarta', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/0671b2cb-ae3d-477b-99b1-9f6184bb4d22.webp', true, '2026-05-20 14:52:10', '2026-05-20 16:45:14', -7.7894000, 110.3636000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('dbdb411c-4e6d-4e2f-b587-2fbbbf258fe7', 'c7d65290-a322-4ded-8222-f2faf11f7401', 'Pantai Ketawang Purworejo', 'Pantai eksotis di Purworejo Selatan dengan pasir hitam vulkanik dan deburan ombak Samudra Hindia yang dramatis. Suasana yang tenang dan belum terlalu ramai menjadikan Ketawang sebagai hidden gem bagi wisatawan yang mencari ketenangan.', 'Grabag, Purworejo, Jawa Tengah', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/dbdb411c-4e6d-4e2f-b587-2fbbbf258fe7.webp', true, '2026-05-20 14:55:30', '2026-05-20 16:45:54', -7.8102445, 109.8762126, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('1db5bce8-5371-4215-9949-f8637e6e1923', '87d916fe-4fa3-4e02-b852-cf6e369ee56e', 'Industri Marmer Tulungagung', 'Tulungagung adalah penghasil marmer terbesar di Indonesia dengan batu marmer berkualitas ekspor. Puluhan showroom dan bengkel pengolahan marmer tersebar di kawasan Campurdarat, menjual berbagai produk marmer — lantai, patung, aksesori — langsung dari produsen.', 'Sentra Marmer, Campurdarat, Tulungagung', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/1db5bce8-5371-4215-9949-f8637e6e1923.webp', true, '2026-05-20 14:56:14', '2026-05-20 16:46:10', -8.0653000, 111.9019000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('0b95abeb-051c-4824-a839-369a1c3f6fa7', '2683ba42-ba6f-4a6a-bb9c-1c1878f01889', 'Kawasan Wisata Selo (Gunung Merapi-Merbabu)', 'Kawasan wisata alam di perbatasan Boyolali-Magelang dengan panorama Gunung Merapi dan Merbabu yang memukau. Camping ground, kebun stroberi, dan sunrise yang spektakuler dari Bukit Klangon tersedia di sini untuk para pencinta alam.', 'Desa Selo, Boyolali, Jawa Tengah', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/0b95abeb-051c-4824-a839-369a1c3f6fa7.webp', true, '2026-05-20 14:55:15', '2026-05-20 16:46:17', -7.5087850, 110.7335400, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('e5d3774a-4929-4e81-acc1-360a4712e43e', '93e682a5-bb4d-4ecb-b4bc-81449842407a', 'Kain Tenun Baduy', 'Kain tenun tradisional buatan tangan Suku Baduy yang menggunakan pewarna alami dari tanaman hutan. Motif-motif geometris khas Baduy yang dibuat tanpa alat modern menjadikan kain ini memiliki nilai budaya dan koleksi yang tinggi.', 'Rangkasbitung, Lebak, Banten', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/e5d3774a-4929-4e81-acc1-360a4712e43e.webp', true, '2026-05-20 14:54:59', '2026-05-20 16:46:19', -6.3527788, 106.2515252, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('05994ce5-c3ca-4d15-a568-56c39b9d8fa5', '1e53b655-0ef3-4d70-8af0-2a8551361f74', 'Sentra Batik Sukoharjo', 'Sukoharjo adalah salah satu pusat produksi batik dan lurik terbesar di Solo Raya. Ratusan pabrik dan pengrajin batik tulis, batik cap, dan lurik tersebar di Sukoharjo dengan harga grosir langsung dari produsen.', 'Sentra Batik Sukoharjo, Jl. Solo-Wonogiri', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/05994ce5-c3ca-4d15-a568-56c39b9d8fa5.webp', true, '2026-05-20 14:55:23', '2026-05-20 16:46:27', -7.6797595, 110.8433721, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('917ab56d-56a1-427f-b26e-570c1653fab2', 'bc07fd7f-2986-49c8-a534-c05d147a2cad', 'Nasi Uduk Kebon Kacang', 'Nasi uduk legendaris yang sudah berdiri sejak puluhan tahun. Disajikan dengan lauk lengkap seperti ayam goreng, semur jengkol, dan tempe orek yang gurih.', 'Jl. Kebon Kacang, Tanah Abang, Jakarta Pusat', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/917ab56d-56a1-427f-b26e-570c1653fab2.webp', true, '2026-05-20 14:51:53', '2026-05-20 16:46:30', -6.1902407, 106.8166009, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('6af70765-6ca6-4497-95c6-abe17bed22a0', 'd26192b6-d749-43e2-b251-3f4cc22ebd02', 'Nasi Koyor Kota Lama', 'Kuliner legendaris Semarang sejak 1955. Nasi koyor disajikan dengan urat sapi empuk yang dimasak berjam-jam, gudeg, kering tempe, oseng kacang panjang, dan sambal merah khas Jawa. Hanya buka pagi hingga siang.', 'Jl. Gelatik No.7, Semarang Utara', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/6af70765-6ca6-4497-95c6-abe17bed22a0.webp', true, '2026-05-20 14:52:21', '2026-05-20 16:46:36', -6.9636000, 110.4275000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('af4d0cce-256c-4d1a-ba80-3e06af0c6469', 'da5a1a86-293c-48ae-ac9a-2d3665db70bb', 'Mie Ayam Bangka Amat Jatinegara', 'Mie ayam Bangka legendaris di kawasan Jatinegara yang sudah buka sejak 1970-an. Mie kenyal buatan sendiri dengan topping ayam jamur yang gurih, bakso, dan pangsit — disajikan dengan kuah kaldu ayam bening yang wangi.', 'Jl. Matraman Raya, Jatinegara, Jakarta Timur', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/af4d0cce-256c-4d1a-ba80-3e06af0c6469.webp', true, '2026-05-20 14:53:27', '2026-05-20 16:46:38', -6.2120431, 106.8608737, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('6dc9e391-e9fc-45af-b175-f22c9d26cc43', '889a7b5b-d310-43ca-8f19-3975012b6361', 'Pusat Oleh Oleh Khas Bekasi, Tempat Asik Buat Borong Camilan Unik!', '## Asbaland Developer. ## Pusat Oleh-Oleh Khas Bekasi, Tempat Asik Buat Borong Camilan Unik! Di sini, Anda bisa menemukan berbagai camilan unik yang cocok untuk dibawa pulang atau dijadikan buah tangan. Yuk, intip beberapa pusat oleh oleh khas Bekasi yang wajib Anda kunjungi! Pasar Proyek Bekasi adalah salah satu tempat yang terkenal sebagai pusat oleh oleh khas. Anda bisa menemukan berbagai camilan tradisional seperti dodol Bekasi, kue rangi, dan kue akar kelapa.', 'Kranji, Bekasi', 'UMKM', 4.30, 'https://cdn.jejakjalur.project-n.site/destinasi/6dc9e391-e9fc-45af-b175-f22c9d26cc43.webp', false, '2026-05-22 14:28:49', '2026-05-22 14:51:20', NULL, -6.2245133, 106.9798267, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('ab539b94-1d47-4579-826d-266e38332afa', '8fd0e42c-3052-4388-a1fb-decd0c71aaeb', 'Api Abadi Mrapen', 'Api abadi yang tidak pernah padam selama berabad-abad karena gas alam yang keluar dari dalam bumi. Api Mrapen sering digunakan sebagai sumber nyala Obor PON dan berbagai upacara ritual keagamaan. Fenomena geologi langka yang hanya ada di beberapa tempat di dunia.', 'Desa Manggarmas, Godong, Grobogan', 'Wisata', 4.33, NULL, true, '2026-05-20 14:55:12', '2026-05-20 16:46:16', -7.2186589, 110.9000211, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('42785b93-8319-42fd-a99d-5f9fb261010b', '8bd7d53c-86dd-4cc9-b272-8556c0128d55', 'Keraton Kanoman', 'Istana Kanoman yang megah dengan koleksi benda pusaka, kereta kencana, dan artefak Kesultanan Cirebon yang berharga.', 'Cirebon Kota', 'Wisata', 4.20, NULL, true, '2026-05-22 23:41:49', '2026-05-22 23:41:49', NULL, -6.7250000, 108.5720000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('5f0835a5-afc8-4e39-9ff3-61110410db9c', '085c1603-d1f3-4aa2-8d9a-e1615f8d925a', 'Dimsum Mentai', 'Es Teler Teko 1 Liter: Mie Viral di Karawang! Nikmati Es Teler Teko dengan porsi unik di Mie Jebew, Kosambi! Dapatkan diskon 10% dan promo', 'Kosambi, Karawang', 'Kuliner', 3.80, 'https://cdn.jejakjalur.project-n.site/destinasi/5f0835a5-afc8-4e39-9ff3-61110410db9c.webp', false, '2026-05-22 14:28:29', '2026-05-22 14:51:17', NULL, -6.3690828, 107.3747867, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('6c5bcabf-2f76-443b-b5e7-58e35ac6bc31', '82d1b189-c47b-4521-967b-de2b916acfd9', 'Brem Madiun Sido Maju', 'Produsen brem khas Madiun yang terkenal sejak puluhan tahun. Brem adalah makanan olahan dari fermentasi beras ketan yang memiliki rasa manis asam unik, tersedia dalam bentuk padat dan cair. Oleh-oleh khas yang paling dicari dari Madiun.', 'Jl. Mayjend Sungkono, Mejayan, Madiun', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/6c5bcabf-2f76-443b-b5e7-58e35ac6bc31.webp', true, '2026-05-20 14:53:02', '2026-05-20 16:32:23', -7.6300000, 111.5292000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('fff9964f-5fa8-4cb9-b473-1f5778f66ed0', '7a56e769-d853-4d95-b830-676ae09b1e77', 'Sego Megono Mbah Ibah', 'Nasi megono autentik khas Pekalongan — nasi dicampur nangka muda cincang halus yang dibumbui dengan parutan kelapa dan rempah. Disantap bersama tempe mendoan panas, tahu bacem, dan lauk lainnya. Sarapan pagi paling ikonik di Pekalongan.', 'Alun-Alun Pekalongan, Pekalongan Utara', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/fff9964f-5fa8-4cb9-b473-1f5778f66ed0.webp', true, '2026-05-20 14:53:09', '2026-05-20 16:32:34', -6.8881000, 109.6731000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('07e5a02e-7e1c-4931-a844-b5f9fc35efd8', '2cdfd1f7-ea94-4248-8f39-24478e961033', 'Pecel Blitar Bu Tri', 'Pecel khas Blitar dengan bumbu kacang yang kaya rempah dan lebih pedas dibanding pecel Madiun. Disajikan dengan aneka sayuran rebus segar, peyek kacang, tempe goreng, dan lauk pilihan. Sarapan andalan warga Blitar sejak puluhan tahun.', 'Jl. Kenanga, Sananwetan, Blitar', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/07e5a02e-7e1c-4931-a844-b5f9fc35efd8.webp', true, '2026-05-20 14:52:55', '2026-05-20 16:32:48', -7.9582526, 112.6559988, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('64af9ebe-6e5a-4366-85cd-4b8f4b74e7a9', '50c3df44-987e-4e6e-bf1b-c4db867fcb08', 'Es Krim Ragusa', 'Es krim Italia legendaris Jakarta sejak 1932 dengan resep original yang tidak pernah berubah. Disajikan di kedai bergaya colonial vintage, Es Krim Ragusa menawarkan cita rasa nostalgia dengan varian klasik seperti es krim durian dan stracciatella.', 'Jl. Veteran I No.10, Gambir, Jakarta Pusat', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/64af9ebe-6e5a-4366-85cd-4b8f4b74e7a9.webp', true, '2026-05-20 14:53:38', '2026-05-20 16:35:48', -6.1620350, 106.7896101, NULL) ON CONFLICT (id) DO NOTHING;
