INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('98701e96-e4f3-49ed-aa5b-5f2717a0f71b', '4b72caad-8fc6-4278-979d-053bfc5b8bf3', 'Situ Gintung', 'Danau buatan seluas 31 hektare di Ciputat yang telah direvitalisasi menjadi kawasan wisata alam dan olahraga. Area jogging, bersepeda, perahu dayung, dan berbagai kuliner pinggir danau tersedia di sini.', 'Jl. Situ Gintung, Ciputat, Tangerang Selatan', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/98701e96-e4f3-49ed-aa5b-5f2717a0f71b.webp', true, '2026-05-20 14:54:26', '2026-05-20 16:36:47', -6.3061813, 106.7630838, NULL) ON CONFLICT (id) DO NOTHING;
