INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('24fdd9c9-3492-4a23-8344-96b26e4f7831', '2a91ea0c-96d1-4dc5-bdba-b9b98f83f5a1', 'Galendo (Ampas Minyak Kelapa) Ciamis', 'Galendo adalah makanan khas Ciamis berupa ampas minyak kelapa yang kering dan renyah dengan rasa gurih-manis unik. Diproduksi secara tradisional oleh UMKM Ciamis dan sulit ditemukan di daerah lain, menjadikannya oleh-oleh eksklusif.', 'Sentra Galendo, Ciamis, Jawa Barat', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/24fdd9c9-3492-4a23-8344-96b26e4f7831.webp', true, '2026-05-20 14:54:52', '2026-05-20 16:39:00', -7.3293002, 108.3561326, NULL) ON CONFLICT (id) DO NOTHING;
