INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('747b18b6-dc8f-4d5c-b50f-8f04a1f4adfb', 'a9a7d381-9880-420e-89a2-d16d604f72f2', 'Waduk Gajah Mungkur', 'Waduk terbesar di Jawa Tengah dengan luas 8.800 hektare yang dikelilingi perbukitan hijau. Fasilitas wisata air lengkap — kapal motor, perahu, ski air, dan pemancingan — tersedia di sini. Panorama sunset di atas waduk menjadi daya tarik utama.', 'Kecamatan Wonogiri, Wonogiri, Jawa Tengah', 'Wisata', 4.33, NULL, true, '2026-05-20 14:55:24', '2026-05-20 16:45:58', -7.8141980, 110.9259617, NULL) ON CONFLICT (id) DO NOTHING;
