INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('466b61a0-7c1a-4256-9774-e45876ac6522', '7c6aa826-60b4-41a3-ac80-cdcd85dce3f8', 'Gudeg Yu Djum', 'Gudeg legendaris Yogyakarta yang sudah berdiri sejak 1950. Gudeg basah dengan cita rasa manis gurih khas Jogja, disajikan dengan krecek, ayam kampung, dan telur.', 'Jl. Kaliurang KM 4.5, Sleman', 'Kuliner', 4.67, 'https://cdn.jejakjalur.project-n.site/destinasi/466b61a0-7c1a-4256-9774-e45876ac6522.webp', true, '2026-05-20 14:52:07', '2026-05-20 16:29:20', -7.8146485, 110.3661371, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('6dc2bc9f-284e-4046-99da-37b32d6e7a28', '25c4d072-5661-4cf6-9225-9d99660339f9', 'Monumen Simpang Lima Gumul', 'Monumen megah terinspirasi Arc de Triomphe Paris yang menjadi landmark Kabupaten Kediri. Dikelilingi lima jalan besar, kawasan ini ramai di malam hari dengan berbagai pedagang kuliner dan jajanan khas Kediri.', 'Desa Tugurejo, Ngasem, Kediri', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/6dc2bc9f-284e-4046-99da-37b32d6e7a28.webp', true, '2026-05-20 14:52:59', '2026-05-20 16:32:13', -7.8217000, 112.0114000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('7efc2aac-5ef1-4744-8aac-787311ef5826', 'd26192b6-d749-43e2-b251-3f4cc22ebd02', 'Semarang Kreatif Galeri', 'Pusat UMKM premium Semarang yang menjual produk 100% handmade karya warga lokal. Koleksi meliputi tas batik, aksesori, kain tenun, hingga kuliner oleh-oleh khas Semarang yang dikemas modern dan siap kirim.', 'Jl. Sriwijaya No.29, Semarang Selatan', 'UMKM', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/7efc2aac-5ef1-4744-8aac-787311ef5826.webp', true, '2026-05-20 14:52:24', '2026-05-20 16:31:00', -6.9636000, 110.4275000, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.destinasi (id, stasiun_id, nama, deskripsi, alamat, kategori, rating, foto, is_verified, created_at, updated_at, lat, lng, user_id) VALUES ('9097029c-0430-4b03-a401-7aea9a7a7015', '7c6aa826-60b4-41a3-ac80-cdcd85dce3f8', 'Keraton Ngayogyakarta Hadiningrat', 'Istana resmi Kesultanan Yogyakarta yang masih aktif hingga kini. Bangunan berarsitektur Jawa klasik ini menyimpan koleksi benda-benda kerajaan bersejarah.', 'Jl. Rotowijayan Blok No.1, Kraton, Yogyakarta', 'Wisata', 4.33, 'https://cdn.jejakjalur.project-n.site/destinasi/9097029c-0430-4b03-a401-7aea9a7a7015.webp', true, '2026-05-20 14:52:06', '2026-05-20 16:29:37', -7.8075974, 110.3638696, NULL) ON CONFLICT (id) DO NOTHING;
